                assign mem_wr_rdn_s1_o = mem_wr_rdn_s1_i ; 
                assign mem_req_s0_o = mem_req_s0_i ; 
                assign mem_req_s1_o = mem_req_s1_i ; 
                assign ahbl_ready_s0_o = 1'b1 ; 
                assign ahbl_ready_s1_o = 1'b1 ; 
            end
    endgenerate
endmodule



`timescale 1ns/1ps
// =============================================================================
