module sys_mem_ipgen_lscc_ahblmem_subordinate #(parameter DATA_WIDTH = 32, 
        parameter ADDR_DEPTH = 16384, 
        parameter ADDR_WIDTH = clog2((((ADDR_DEPTH - 1) * DATA_WIDTH) / 8)), 
        parameter REG_MODE = "noreg", 
        parameter BYTE_ENABLE = 1, 
        parameter START_ADDR = 0, 
        parameter END_ADDR = (((ADDR_DEPTH * DATA_WIDTH) / 8) - 1), 
        parameter PORT_TYPE = "R/W", 
        parameter RESET_MODE = "sync", 
        parameter BYTE_WIDTH = (DATA_WIDTH / 8), 
        parameter UNALIGNED_EN = 0, 
        parameter UNALIGNED_DIR = "none", 
        parameter READ_PIPELINE = 0, 
        parameter MEMORY_TYPE = "EBR") (
    input ahbl_hclk_i, 
    input ahbl_hresetn_i, 
    // ------------------------   
    // AHB-Lite Interface         
    // ------------------------   
    input ahbl_hsel_i, 
    input ahbl_hready_i, 
    input [31:0] ahbl_haddr_i, 
    input [2:0] ahbl_hburst_i, 
    input [2:0] ahbl_hsize_i, 
    input ahbl_hmastlock_i,  // currently not used
    input [3:0] ahbl_hprot_i,  // currently not used
    input [1:0] ahbl_htrans_i, 
    input ahbl_hwrite_i, 
    input [(DATA_WIDTH - 1):0] ahbl_hwdata_i, 
    output reg ahbl_hreadyout_o, 
    output reg ahbl_hresp_o, 
    output [(DATA_WIDTH - 1):0] ahbl_hrdata_o, 
    // ------------------------
    // Memory Interface           
    // ------------------------
    input [(DATA_WIDTH - 1):0] mem_rdata_i, 
    input mem_error_i, 
    output reg mem_request_o, 
    output mem_wr_rdn_o, 
    output [(ADDR_WIDTH - 1):0] mem_addr_o, 
    output [(DATA_WIDTH - 1):0] mem_wdata_o, 
    output [(BYTE_WIDTH - 1):0] mem_byte_en_o, 
    // Arbiter
    input arb_hready_i) ;
    // ------------------------------------------------------------------------------
    // Local Parameters
    // ------------------------------------------------------------------------------
    localparam ADDR_INCR_SIZE_WIDTH = clog2((DATA_WIDTH / 8)) ; 
    localparam BYTE_EN_POL = ((MEMORY_TYPE == "LRAM") ? 1'b0 : 1'b1) ; 
    localparam BYTE_EN_NEG = ((MEMORY_TYPE == "LRAM") ? 1'b1 : 1'b0) ; 
    localparam REG_MODE_EBR = ((REG_MODE == "reg") & (MEMORY_TYPE == "EBR")) ; 
    localparam REG_MODE_LRAM = ((REG_MODE == "reg") & (MEMORY_TYPE == "LRAM")) ; 
    localparam REG_MODE_DRAM = ((REG_MODE == "reg") & (MEMORY_TYPE == "Distributed_RAM")) ; 
    // AHBL STATE
    localparam [1:0] AHBL_IDLE = 2'b00 ; 
    localparam [1:0] AHBL_READ = 2'b01 ; 
    localparam [1:0] AHBL_WRITE = 2'b10 ; 
    localparam [1:0] AHBL_ERROR = 2'b11 ; 
    // HBURST commands                         
    localparam [2:0] SINGLE = 3'b000 ; 
    localparam [2:0] INCR = 3'b001 ; 
    localparam [2:0] WRAP4 = 3'b010 ; 
    localparam [2:0] INCR4 = 3'b011 ; 
    localparam [2:0] WRAP8 = 3'b100 ; 
    localparam [2:0] INCR8 = 3'b101 ; 
    localparam [2:0] WRAP16 = 3'b110 ; 
    localparam [2:0] INCR16 = 3'b111 ; 
    // HTRANS commands
    localparam [1:0] IDLE = 2'b00 ; 
    localparam [1:0] BUSY = 2'b01 ; 
    localparam [1:0] NSEQ = 2'b10 ; 
    localparam [1:0] SEQ = 2'b11 ; 
    // HSIZE transactions
    localparam [2:0] X32_DATA = 3'b010 ; 
    localparam [2:0] X16_DATA = 3'b001 ; 
    localparam [2:0] X8_DATA = 3'b000 ; 
    // ------------------------------------------------------------------------------
    // Wire and Register Declarations
    // ------------------------------------------------------------------------------
    wire slv_sel ; 
    // Output Wires
    wire [(ADDR_WIDTH - 1):0] mem_addr_w ; 
    wire [31:0] ahbl_haddr_w ; 
    // Unaligned and Byte Enable Tx
    reg [(BYTE_WIDTH - 1):0] unaligned_ctrl_w ; 
    reg [(BYTE_WIDTH - 1):0] ben_w ; 
    // Error Detect
    wire AHBL_ok_w ; 
    wire AHBL_unaligned_w ; 
    wire AHBL_misaccess_w ; 
    wire AHBL_overflow_w ; 
    wire AHBL_overwidth_w ; 
    wire AHBL_reg_wrap_w ; 
    // Write Address FIFO
    reg ahbl_raddrq_wren ; 
    reg [(ADDR_WIDTH + 3):0] ahbl_raddrq_in ; //[31:0] - write addr [34:32] - write hsize, [35] wr_rdn
    reg ahbl_raddrq_rden ; 
    wire [(ADDR_WIDTH + 3):0] ahbl_raddrq_out ; //[31:0] - write addr [34:32] - write hsize, , [35] wr_rdn
    wire ahbl_raddrq_empty ; 
    wire ahbl_raddrq_full ; 
    wire ahbl_hwrite_p_r ; 
    wire [2:0] ahbl_hsize_p_r ; 
    wire [31:0] ahbl_raddr_p_r ; 
    reg [4:0] addr_count ; 
    // Write Data FIFO
    wire ahbl_wdataq_wren ; 
    wire [(DATA_WIDTH - 1):0] ahbl_wdataq_in ; 
    wire ahbl_wdataq_rden ; 
    wire [(DATA_WIDTH - 1):0] ahbl_wdataq_out ; 
    wire ahbl_wdataq_empty ; 
    wire ahbl_wdataq_full ; 
    // Read Data FIFO
    wire ahbl_rdatq_wren ; 
    wire ahbl_rdatq_rden ; 
    wire [(DATA_WIDTH - 1):0] ahbl_rdatq_out ; 
    wire ahbl_rdatq_empty ; 
    wire [1:0] ahbl_rdatq_full ; 
    wire ahblr_rdatq_full ; 
    wire ahblr_rdatq_afull ; 
    // State Machine
    reg [1:0] ahbl_state ; 
    reg [1:0] ahbl_state_next ; 
    // ahbl ready
    reg ahbl_hreadyout_r ; 
    // Read ahead
    reg [31:0] raddr_ahead ; 
    wire fifo_clr ; 
    // If reg mode is true, expect delay in rdata valid from memory
    wire ahbl_rdatq_wren_d ; 
    reg request_valid ; 
    reg request_valid_d ; 
    reg request_valid_q ; 
    reg arb_hready_d ; 
    wire [4:0] undefined_addr_count_constant ; 
    // ------------------------------------------------------------------------------
    // Logic Start
    // ------------------------------------------------------------------------------
    // State Machine
    always
        @(posedge ahbl_hclk_i or 
            negedge ahbl_hresetn_i)
        begin
            if ((~ahbl_hresetn_i)) 
                begin
                    ahbl_state <=  AHBL_IDLE ;
                end
            else
                begin
                    ahbl_state <=  ahbl_state_next ;
                end
        end
    always
        @(*)
        begin
            case (ahbl_state)
            AHBL_IDLE : 
                begin
                    if ((~AHBL_ok_w)) 
                        begin
                            ahbl_state_next = AHBL_ERROR ;
                        end
                    else
                        if ((((ahbl_htrans_i == NSEQ) & ahbl_hsel_i) & ahbl_hready_i)) 
                            begin
                                if (ahbl_hwrite_i) 
                                    begin
                                        ahbl_state_next = AHBL_WRITE ;
                                    end
                                else
                                    begin
                                        ahbl_state_next = AHBL_READ ;
                                    end
                            end
                        else
                            begin
                                ahbl_state_next = AHBL_IDLE ;
                            end
                end
            AHBL_WRITE : 
                if ((~AHBL_ok_w)) 
                    begin
                        ahbl_state_next = AHBL_ERROR ;
                    end
                else
                    if ((ahbl_htrans_i == IDLE)) 
                        begin
                            ahbl_state_next = AHBL_IDLE ;
                        end
                    else
                        if ((((ahbl_htrans_i == NSEQ) & ahbl_hsel_i) & ahbl_hreadyout_o)) 
                            begin
                                if (ahbl_hwrite_i) 
                                    begin
                                        ahbl_state_next = AHBL_WRITE ;
                                    end
                                else
                                    begin
                                        ahbl_state_next = AHBL_READ ;
                                    end
                            end
                        else
                            begin
                                ahbl_state_next = AHBL_WRITE ;
                            end
            AHBL_READ : 
                begin
                    if ((~AHBL_ok_w)) 
                        begin
                            ahbl_state_next = AHBL_ERROR ;
                        end
                    else
                        if (((ahbl_htrans_i == IDLE) & ahbl_hreadyout_o)) 
                            begin
                                ahbl_state_next = AHBL_IDLE ;
                            end
                        else
                            if ((((ahbl_htrans_i == NSEQ) & ahbl_hsel_i) & ahbl_hreadyout_o)) 
                                begin
                                    if (ahbl_hwrite_i) 
                                        begin
                                            ahbl_state_next = AHBL_WRITE ;
                                        end
                                    else
                                        begin
                                            ahbl_state_next = AHBL_READ ;
                                        end
                                end
                            else
                                if ((((ahbl_htrans_i == SEQ) & ahbl_hsel_i) & ahbl_hreadyout_o)) 
                                    begin
                                        ahbl_state_next = AHBL_READ ;
                                    end
                                else
                                    begin
                                        ahbl_state_next = AHBL_READ ;
                                    end
                end
            AHBL_ERROR : 
                if (((ahbl_htrans_i == IDLE) & ahbl_hreadyout_o)) 
                    begin
                        ahbl_state_next = AHBL_IDLE ;
                    end
                else
                    begin
                        ahbl_state_next = AHBL_ERROR ;
                    end
            default : 
                begin
                    // IDLE
                    if ((~AHBL_ok_w)) 
                        begin
                            ahbl_state_next = AHBL_ERROR ;
                        end
                    else
                        if ((((ahbl_htrans_i == NSEQ) & ahbl_hsel_i) & ahbl_hready_i)) 
                            begin
                                if (ahbl_hwrite_i) 
                                    begin
                                        ahbl_state_next = AHBL_WRITE ;
                                    end
                                else
                                    begin
                                        ahbl_state_next = AHBL_READ ;
                                    end
                            end
                        else
                            begin
                                ahbl_state_next = AHBL_IDLE ;
                            end
                end
            endcase 
        end
    // Wires
    assign slv_sel = (ahbl_hsel_i & (ahbl_htrans_i != IDLE)) ; 
    // Output to memory
    // Memory Request Out
    always
        @(*)
        begin
            case (ahbl_state)
            AHBL_WRITE,
                    IDLE : 
                mem_request_o = (~ahbl_wdataq_empty) ;
            default : 
                mem_request_o = (~ahbl_raddrq_empty) ;
            endcase 
        end
    // Memory Write Readn Out
    assign mem_wr_rdn_o = (ahbl_hwrite_p_r & (~ahbl_wdataq_empty)) ; 
    // Memory Address Out
    assign mem_addr_o = {{ADDR_INCR_SIZE_WIDTH{1'b0}},
                mem_addr_w[(ADDR_WIDTH - 1):ADDR_INCR_SIZE_WIDTH]} ; 
    assign mem_addr_w = ahbl_raddr_p_r[(ADDR_WIDTH - 1):0] ; 
    reg [31:0] ahead_incr ; 
    wire [31:0] raddr_ahead_next ; 
    assign raddr_ahead_next = (raddr_ahead + ahead_incr) ; 
    always
        @(posedge ahbl_hclk_i or 
            negedge ahbl_hresetn_i)
        begin
            if ((~ahbl_hresetn_i)) 
                begin
                    raddr_ahead <=  32'h0 ;
                end
            else
                begin
                    if (((ahbl_htrans_i == NSEQ) & (~ahbl_hwrite_i))) 
                        begin
                            // starting value
                            raddr_ahead <=  {{(32 - ADDR_WIDTH){1'b0}},
                                    ahbl_haddr_w[(ADDR_WIDTH - 1):0]} ;
                        end
                    else
                        begin
                            if ((ahbl_raddrq_wren & (~ahbl_hwrite_i))) 
                                begin
                                    raddr_ahead <=  ((~(raddr_ahead_next > END_ADDR)) ? raddr_ahead_next : raddr_ahead) ;
                                end
                        end
                end
        end
    always
        @(*)
        begin
            // X32
            case (ahbl_hsize_i)
            X8_DATA : 
                ahead_incr = 32'h1 ;
            X16_DATA : 
                ahead_incr = 32'h2 ;
            default : 
                ahead_incr = 32'h4 ;
            endcase 
        end
    // Memory Write Data Out
    assign mem_wdata_o = ahbl_wdataq_out ; 
    // Memory Byte Enable Out
    // if LRAM, mem_byte_en_o is active low
    assign mem_byte_en_o = ((MEMORY_TYPE == "LRAM") ? (ahbl_hwrite_p_r ? ben_w : unaligned_ctrl_w) : ben_w) ; 
    always
        @(*)
        begin
            //ben_w
            if ((BYTE_ENABLE == 1)) 
                begin
                    case (DATA_WIDTH)
                    32 : 
                        begin
                            ben_w = ((ahbl_hsize_p_r == X32_DATA) ? {4{BYTE_EN_POL}} : ((ahbl_hsize_p_r == X16_DATA) ? ((ahbl_raddr_p_r[1] == 1) ? {{2{BYTE_EN_POL}},
                                    {2{BYTE_EN_NEG}}} : {{2{BYTE_EN_NEG}},
                                    {2{BYTE_EN_POL}}}) : ((ahbl_raddr_p_r[1:0] == 3) ? {BYTE_EN_POL,
                                    {3{BYTE_EN_NEG}}} : ((ahbl_raddr_p_r[1:0] == 2) ? {BYTE_EN_NEG,
                                    BYTE_EN_POL,
                                    {2{BYTE_EN_NEG}}} : ((ahbl_raddr_p_r[1:0] == 1) ? {{2{BYTE_EN_NEG}},
                                    BYTE_EN_POL,
                                    BYTE_EN_NEG} : {{3{BYTE_EN_NEG}},
                                    BYTE_EN_POL}))))) ;
                        end
                    16 : 
                        begin
                            ben_w = ((ahbl_hsize_p_r == X16_DATA) ? {2{BYTE_EN_POL}} : ((ahbl_raddr_p_r[0] == 1) ? {BYTE_EN_POL,
                                    BYTE_EN_NEG} : {BYTE_EN_NEG,
                                    BYTE_EN_POL})) ;//hsize 8-bit
                        end
                    default : 
                        ben_w = {BYTE_WIDTH{BYTE_EN_POL}} ;
                    endcase 
                end
            else
                begin
                    ben_w = {BYTE_WIDTH{BYTE_EN_POL}} ;
                end
        end
    always
        @(*)
        begin
            if ((UNALIGNED_EN == 1)) 
                begin
                    unaligned_ctrl_w = ((UNALIGNED_DIR == "right") ? {{2'b00},
                            {mem_addr_w[1:0]}} : ((UNALIGNED_DIR == "left") ? {{2'b01},
                            {mem_addr_w[1:0]}} : 4'b000)) ;
                end
            else
                begin
                    if ((MEMORY_TYPE == "EBR")) 
                        begin
                            unaligned_ctrl_w = {BYTE_WIDTH{1'b1}} ;
                        end
                    else
                        begin
                            unaligned_ctrl_w = {BYTE_WIDTH{1'b0}} ;
                        end
                end
        end
    always
        @(posedge ahbl_hclk_i or 
            negedge ahbl_hresetn_i)
        begin
            if ((~ahbl_hresetn_i)) 
                begin
                    ahbl_hresp_o <=  1'b0 ;
                end
            else
                begin
                    ahbl_hresp_o <=  ((ahbl_state == AHBL_ERROR) & (~((ahbl_htrans_i == IDLE) & ahbl_hready_i))) ;
                end
        end
    // 
    always
        @(*)
        begin
            ahbl_hreadyout_o = ((ahbl_state == AHBL_READ) ? (~ahbl_rdatq_empty) : (ahbl_hreadyout_r & (~ahbl_raddrq_full))) ;
        end
    always
        @(posedge ahbl_hclk_i or 
            negedge ahbl_hresetn_i)
        begin
            if ((~ahbl_hresetn_i)) 
                begin
                    ahbl_hreadyout_r <=  1'b1 ;
                end
            else
                begin
                    case (ahbl_state_next)
                    AHBL_ERROR : 
                        ahbl_hreadyout_r <=  ahbl_hresp_o ;
                    default : 
                        ahbl_hreadyout_r <=  AHBL_ok_w ;
                    endcase 
                end
        end
    assign AHBL_ok_w = (((((AHBL_unaligned_w & AHBL_overflow_w) & AHBL_misaccess_w) & AHBL_overwidth_w) & (~mem_error_i)) & (~AHBL_reg_wrap_w)) ; 
    generate
        if (UNALIGNED_EN) 
            begin : genblk1
                assign AHBL_unaligned_w = 1'b1 ; 
            end
        else
            begin : genblk1
                assign AHBL_unaligned_w = ((DATA_WIDTH == 32) ? ((ahbl_hsize_i == X32_DATA) ? ((ahbl_haddr_w[1:0] == 2'b00) ? 1'b1 : (~slv_sel)) : ((ahbl_hsize_i == X16_DATA) ? ((ahbl_haddr_w[0] == 1'b0) ? 1'b1 : (~slv_sel)) : 1'b1)) : ((DATA_WIDTH == 16) ? ((ahbl_hsize_i == X16_DATA) ? ((ahbl_haddr_w[0] == 1'b0) ? 1'b1 : (~slv_sel)) : 1'b1) : 1'b1)) ; 
            end
    endgenerate
    assign AHBL_misaccess_w = ((PORT_TYPE == "R/O") ? ((ahbl_hwrite_i == 1'b0) ? 1'b1 : (~slv_sel)) : 1'b1) ; 
    assign AHBL_overflow_w = ((~(ahbl_haddr_w[31:0] > END_ADDR)) | (~(ahbl_hreadyout_o & slv_sel))) ; 
    assign AHBL_overwidth_w = ((DATA_WIDTH == 32) ? 1'b1 : ((DATA_WIDTH == 16) ? ((ahbl_hsize_i == X32_DATA) ? (~slv_sel) : 1'b1) : ((ahbl_hsize_i == X8_DATA) ? 1'b1 : (~slv_sel)))) ; 
    assign AHBL_reg_wrap_w = (((REG_MODE == "reg") & (ahbl_hwrite_i == 1'b0)) & (((ahbl_hburst_i == WRAP4) | (ahbl_hburst_i == WRAP8)) | (ahbl_hburst_i == WRAP16))) ; // WRAP is not supported
    assign ahbl_haddr_w = (ahbl_haddr_i + START_ADDR) ; 
    // Request Address FIFO 
    always
        @(*)
        begin
            // IDLE
            case (ahbl_state)
            AHBL_READ : 
                ahbl_raddrq_wren = (((((addr_count != 5'h0) & (~ahbl_raddrq_full)) & (~(((ahbl_htrans_i == NSEQ) & (addr_count == 5'h1)) & (~ahbl_hwrite_i)))) & (~ahblr_rdatq_afull)) || (((((ahbl_hreadyout_o & (~ahbl_raddrq_full)) & ahbl_hwrite_i) & ahbl_htrans_i[1]) & AHBL_ok_w) & ahbl_hsel_i)) ;
            default : 
                ahbl_raddrq_wren = (((((ahbl_hreadyout_o & (~ahbl_raddrq_full)) & ahbl_hwrite_i) & ahbl_htrans_i[1]) & AHBL_ok_w) & ahbl_hsel_i) ;
            endcase 
        end
    always
        @(*)
        begin
            case (ahbl_state)
            AHBL_READ : 
                begin
                    if ((((ahbl_htrans_i == NSEQ) & ahbl_hwrite_i) & ahbl_hreadyout_o)) 
                        begin
                            ahbl_raddrq_in = {ahbl_hwrite_i,
                                    ahbl_hsize_i[2:0],
                                    ahbl_haddr_w[(ADDR_WIDTH - 1):0]} ;
                        end
                    else
                        begin
                            ahbl_raddrq_in = {1'b0,
                                    ahbl_hsize_i[2:0],
                                    raddr_ahead[(ADDR_WIDTH - 1):0]} ;
                        end
                end
            default : 
                ahbl_raddrq_in = {ahbl_hwrite_i,
                        ahbl_hsize_i[2:0],
                        ahbl_haddr_w[(ADDR_WIDTH - 1):0]} ;
            endcase 
        end
    always
        @(*)
        begin
            case (ahbl_state)
            AHBL_WRITE : 
                ahbl_raddrq_rden = (((~ahbl_wdataq_empty) & (~ahbl_raddrq_empty)) & arb_hready_i) ;
            default : 
                ahbl_raddrq_rden = ((~ahbl_raddrq_empty) & arb_hready_i) ;
            endcase 
        end
    // ahbl_raddrq_out will be assigned to mem_raddr_o when transaction is ongoing
    assign ahbl_hwrite_p_r = ahbl_raddrq_out[(ADDR_WIDTH + 3)] ; 
    assign ahbl_hsize_p_r = ahbl_raddrq_out[(ADDR_WIDTH + 2):ADDR_WIDTH] ; 
    assign ahbl_raddr_p_r = {{(32 - ADDR_WIDTH){1'b0}},
                ahbl_raddrq_out[(ADDR_WIDTH - 1):0]} ; 
    // Address Request FIFO
    always
        @(posedge ahbl_hclk_i or 
            negedge ahbl_hresetn_i)
        begin
            // used to read transaction only
            if ((~ahbl_hresetn_i)) 
                begin
                    addr_count <=  5'h0 ;
                end
            else
                begin
                    if (((ahbl_htrans_i == NSEQ) & ahbl_hreadyout_o)) 
                        begin
                            // SINGLE        
                            case (ahbl_hburst_i)
                            INCR : 
                                addr_count <=  undefined_addr_count_constant ;
                            INCR4 : 
                                //undefined
                                addr_count <=  5'h4 ;
                            INCR8 : 
                                addr_count <=  5'h8 ;
                            INCR16 : 
                                addr_count <=  5'd16 ;
                            default : 
                                addr_count <=  5'd2 ;
                            endcase 
                        end
                    else
                        begin
                            if ((ahbl_hburst_i == INCR)) 
                                begin
                                    if (((ahbl_htrans_i == SEQ) && ahbl_hreadyout_o)) 
                                        begin
                                            // Sequence Read
                                            addr_count <=  5'h1 ;// there is atleast one more read transaction
                                        end
                                    else
                                        begin
                                            if (ahbl_raddrq_wren) 
                                                begin
                                                    addr_count <=  (addr_count - 5'h1) ;
                                                end
                                            else
                                                begin
                                                    addr_count <=  addr_count ;
                                                end
                                        end
                                end
                            else
                                begin
                                    if (ahbl_raddrq_wren) 
                                        begin
                                            addr_count <=  (addr_count - 5'h1) ;
                                        end
                                    else
                                        begin
                                            addr_count <=  addr_count ;
                                        end
                                end
                        end
                end
        end
    always
        @(posedge ahbl_hclk_i or 
            negedge ahbl_hresetn_i)
        begin
            if ((~ahbl_hresetn_i)) 
                begin
                    arb_hready_d <=  1'b0 ;
                end
            else
                begin
                    arb_hready_d <=  arb_hready_i ;
                end
        end
    sys_mem_ipgen_shreg_fifo #(.DWID(((ADDR_WIDTH + 3) + 1)),
            .RNUM(4)) u_ahbl_raddrq (// Address[ADDR_WIDTH] + hsize[3] + hwrite[1]
            // Inputs
            .clk(ahbl_hclk_i), 
                .rst_n(ahbl_hresetn_i), 
                .clr(1'b0), 
                .wren(ahbl_raddrq_wren), 
                .dtin(ahbl_raddrq_in), 
                .rden(ahbl_raddrq_rden), 
                // Outputs
            .dtout(ahbl_raddrq_out), 
                .emty(ahbl_raddrq_empty), 
                .full(ahbl_raddrq_full) /*AUTOINST*/) ; 
    // Write data FIFO
    assign ahbl_wdataq_wren = ((((~ahbl_wdataq_full) & (~ahbl_raddrq_empty)) & (ahbl_state == AHBL_WRITE)) & (~(ahbl_htrans_i == BUSY))) ; 
    assign ahbl_wdataq_in = ahbl_hwdata_i ; 
    assign ahbl_wdataq_rden = ((~ahbl_wdataq_empty) & arb_hready_i) ; 
    generate
        if ((PORT_TYPE == "R/W")) 
            begin : gen_wdata_fifo
                sys_mem_ipgen_shreg_fifo #(.DWID(DATA_WIDTH),
                        .RNUM(4)) u_ahbl_wdataq (// Inputs
                        .clk(ahbl_hclk_i), 
                            .rst_n(ahbl_hresetn_i), 
                            .clr(1'b0), 
                            .wren(ahbl_wdataq_wren), 
                            .dtin(ahbl_wdataq_in), 
                            .rden(ahbl_wdataq_rden), 
                            // Outputs
                        .dtout(ahbl_wdataq_out), 
                            .emty(ahbl_wdataq_empty), 
                            .full(ahbl_wdataq_full) /*AUTOINST*/) ; 
            end
        else
            begin : no_gen_wdata_fifo
                assign ahbl_wdataq_out = {DATA_WIDTH{1'b0}} ; 
                assign ahbl_wdataq_empty = 1'b1 ; 
                assign ahbl_wdataq_full = 1'b0 ; 
            end
    endgenerate
    generate
        if (REG_MODE_LRAM) 
            begin : genblk3
                assign undefined_addr_count_constant = 5'h3 ; // initial hold of address count
            end
        else
            if (REG_MODE_EBR) 
                begin : genblk3
                    assign undefined_addr_count_constant = 5'h4 ; // initial hold of address count        
                end
            else
                if (REG_MODE_DRAM) 
                    begin : genblk3
                        assign undefined_addr_count_constant = 5'h3 ; // initial hold of address count
                    end
                else
                    begin : genblk3
                        assign undefined_addr_count_constant = 5'h4 ; // initial hold of address count
                    end
    endgenerate
    generate
        if (REG_MODE_LRAM) 
            begin : gen_reg_mode_lram
                localparam READ_AFULLVL = 3 ; 
                sys_mem_ipgen_shreg_fifo #(.ENAFULL(1),
                        .DWID(DATA_WIDTH),
                        .RNUM(4),
                        .AFULLVL(READ_AFULLVL)) u_ahbl_rdatq (// Inputs
                        .clk(ahbl_hclk_i), 
                            .rst_n(ahbl_hresetn_i), 
                            .clr(fifo_clr), 
                            .wren(ahbl_rdatq_wren), 
                            .dtin(mem_rdata_i), 
                            .rden(ahbl_rdatq_rden), 
                            // Outputs
                        .dtout(ahbl_rdatq_out), 
                            .emty(ahbl_rdatq_empty), 
                            .full(ahbl_rdatq_full) /*AUTOINST*/) ; 
                assign ahblr_rdatq_full = ahbl_rdatq_full[1] ; 
                assign ahblr_rdatq_afull = ahbl_rdatq_full[0] ; 
                assign ahbl_hrdata_o = (ahbl_rdatq_empty ? {DATA_WIDTH{1'b0}} : ahbl_rdatq_out) ; 
                assign fifo_clr = ((ahbl_hreadyout_o & (ahbl_htrans_i == NSEQ)) & (~ahbl_hwrite_i)) ; 
                assign ahbl_rdatq_wren = (ahbl_rdatq_wren_d & (~ahblr_rdatq_full)) ; // end of count or burst read ongoing
                assign ahbl_rdatq_rden = ((~ahbl_rdatq_empty) & (~(ahbl_htrans_i == BUSY))) ; 
                always
                    @(posedge ahbl_hclk_i or 
                        negedge ahbl_hresetn_i)
                    begin
                        if ((~ahbl_hresetn_i)) 
                            begin
                                request_valid <=  1'b0 ;
                            end
                        else
                            begin
                                if (fifo_clr) 
                                    begin
                                        request_valid <=  1'b0 ;
                                    end
                                else
                                    begin
                                        if ((mem_request_o & (~mem_wr_rdn_o))) 
                                            begin
                                                request_valid <=  arb_hready_i ;
                                            end
                                        else
                                            begin
                                                request_valid <=  1'b0 ;
                                            end
                                    end
                            end
                    end
                always
                    @(posedge ahbl_hclk_i or 
                        negedge ahbl_hresetn_i)
                    begin
                        if ((~ahbl_hresetn_i)) 
                            begin
                                request_valid_d <=  1'b0 ;
                                request_valid_q <=  1'b0 ;
                            end
                        else
                            begin
                                request_valid_d <=  (request_valid & (~(((ahbl_htrans_i == NSEQ) & (~ahbl_hwrite_i)) & (ahbl_hburst_i != SINGLE)))) ;
                                request_valid_q <=  (request_valid_d & (~(((ahbl_htrans_i == NSEQ) & (~ahbl_hwrite_i)) & (ahbl_hburst_i != SINGLE)))) ;
                            end
                    end
                if (READ_PIPELINE) 
                    begin : gen_read_pipeline
                        // 3 Clock latency
                        assign ahbl_rdatq_wren_d = request_valid_q ; 
                    end
                else
                    begin : no_gen_read_pipeline
                        // no PIPELINE is 2 clock latency
                        assign ahbl_rdatq_wren_d = request_valid_d ; 
                    end
            end
        else
            if ((REG_MODE_EBR || REG_MODE_DRAM)) 
                begin : gen_reg_mode_ebr_dram
                    localparam READ_AFULLVL = 3 ; 
                    sys_mem_ipgen_shreg_fifo #(.ENAFULL(1),
                            .DWID(DATA_WIDTH),
                            .RNUM(4),
                            .AFULLVL(READ_AFULLVL)) u_ahbl_rdatq (// Inputs
                            .clk(ahbl_hclk_i), 
                                .rst_n(ahbl_hresetn_i), 
                                .clr(fifo_clr), 
                                .wren(ahbl_rdatq_wren), 
                                .dtin(mem_rdata_i), 
                                .rden(ahbl_rdatq_rden), 
                                // Outputs
                            .dtout(ahbl_rdatq_out), 
                                .emty(ahbl_rdatq_empty), 
                                .full(ahbl_rdatq_full) /*AUTOINST*/) ; 
                    assign ahblr_rdatq_full = ahbl_rdatq_full[1] ; 
                    assign ahblr_rdatq_afull = ahbl_rdatq_full[0] ; 
                    assign ahbl_hrdata_o = (ahbl_rdatq_empty ? {DATA_WIDTH{1'b0}} : ahbl_rdatq_out) ; 
                    assign fifo_clr = ((ahbl_hreadyout_o & (ahbl_htrans_i == NSEQ)) & (~ahbl_hwrite_i)) ; 
                    assign ahbl_rdatq_wren = (ahbl_rdatq_wren_d & (~ahblr_rdatq_full)) ; // end of count or burst read ongoing
                    assign ahbl_rdatq_rden = ((~ahbl_rdatq_empty) & (~(ahbl_htrans_i == BUSY))) ; 
                    always
                        @(posedge ahbl_hclk_i or 
                            negedge ahbl_hresetn_i)
                        begin
                            if ((~ahbl_hresetn_i)) 
                                begin
                                    request_valid <=  1'b0 ;
                                end
                            else
                                begin
                                    if (fifo_clr) 
                                        begin
                                            request_valid <=  1'b0 ;
                                        end
                                    else
                                        begin
                                            if ((mem_request_o & (~mem_wr_rdn_o))) 
                                                begin
                                                    request_valid <=  arb_hready_i ;
                                                end
                                            else
                                                begin
                                                    request_valid <=  1'b0 ;
                                                end
                                        end
                                end
                        end
                    always
                        @(posedge ahbl_hclk_i or 
                            negedge ahbl_hresetn_i)
                        begin
                            if ((~ahbl_hresetn_i)) 
                                begin
                                    request_valid_d <=  1'b0 ;
                                end
                            else
                                begin
                                    request_valid_d <=  (request_valid & (~(((ahbl_htrans_i == NSEQ) & (~ahbl_hwrite_i)) & (ahbl_hburst_i != SINGLE)))) ;
                                end
                        end
                    assign ahbl_rdatq_wren_d = request_valid_d ; 
                end
            else
                begin : no_gen_reg_mode
                    localparam READ_AFULLVL = 2 ; 
                    sys_mem_ipgen_shreg_fifo #(.ENAFULL(1),
                            .DWID(DATA_WIDTH),
                            .RNUM(3),
                            .AFULLVL(READ_AFULLVL)) u_ahbl_rdatq (// Inputs
                            .clk(ahbl_hclk_i), 
                                .rst_n(ahbl_hresetn_i), 
                                .clr(fifo_clr), 
                                .wren(ahbl_rdatq_wren), 
                                .dtin(mem_rdata_i), 
                                .rden(ahbl_rdatq_rden), 
                                // Outputs
                            .dtout(ahbl_rdatq_out), 
                                .emty(ahbl_rdatq_empty), 
                                .full(ahbl_rdatq_full) /*AUTOINST*/) ; 
                    assign ahblr_rdatq_full = ahbl_rdatq_full[1] ; 
                    assign ahblr_rdatq_afull = ahbl_rdatq_full[0] ; 
                    assign ahbl_hrdata_o = (ahbl_rdatq_empty ? {DATA_WIDTH{1'b0}} : ahbl_rdatq_out) ; 
                    ;
                    assign fifo_clr = ((ahbl_hreadyout_o & (ahbl_htrans_i == NSEQ)) & (~ahbl_hwrite_i)) ; 
                    assign ahbl_rdatq_wren = (ahbl_rdatq_wren_d & (~ahblr_rdatq_full)) ; // end of count or burst read ongoing
                    assign ahbl_rdatq_rden = ((~ahbl_rdatq_empty) & (~(ahbl_htrans_i == BUSY))) ; 
                    always
                        @(posedge ahbl_hclk_i or 
                            negedge ahbl_hresetn_i)
                        begin
                            if ((~ahbl_hresetn_i)) 
                                begin
                                    request_valid <=  1'b0 ;
                                end
                            else
                                begin
                                    if (fifo_clr) 
                                        begin
                                            request_valid <=  1'b0 ;
                                        end
                                    else
                                        begin
                                            if ((mem_request_o & (~mem_wr_rdn_o))) 
                                                begin
                                                    request_valid <=  arb_hready_i ;
                                                end
                                            else
                                                begin
                                                    request_valid <=  1'b0 ;
                                                end
                                        end
                                end
                        end
                    assign ahbl_rdatq_wren_d = request_valid ; 
                end
    endgenerate
    // ------------------------------------------------------------------------------
    // Logic End
    // ------------------------------------------------------------------------------
    //------------------------------------------------------------------------------
    // Function Definition
    //------------------------------------------------------------------------------
    function [31:0] clog2 ; 
        input [31:0] value ; 
        reg [31:0] num ; 
        begin
            num = (value - 1) ;
            for (clog2 = 0 ; (num > 0) ; clog2 = (clog2 + 1))
                num = (num >> 1) ;
        end
    endfunction
endmodule



`timescale 1ns/1ps
