module sys_mem_ipgen_lscc_axi4mem_arbiter #(parameter PORT_TYPE_S0 = "R/W", 
        parameter PORT_TYPE_S1 = "R/W", 
        parameter DATA_WIDTH = 32, 
        parameter ADDR_WIDTH = 32, 
        parameter BYTE_WIDTH = (DATA_WIDTH / 8), 
        parameter ARBITER_EN = 0, 
        parameter ATOMIC_ACCESS_EN_S0 = 0, 
        parameter ATOMIC_ACCESS_EN_S1 = 0) (
    // ------------------------------------------------------------------------------
    // Input/Output Ports
    // ------------------------------------------------------------------------------
    input clk_i, 
    input rstn_i, 
    // ------------------------------------------------------------------------------
    // Port S0 Signals
    // ------------------------------------------------------------------------------
    input axi_s0_awpipeline_i, 
    input [(ADDR_WIDTH - 1):0] axi_s0_waddr_i, 
    input axi_s0_wr_en_i, 
    input [(BYTE_WIDTH - 1):0] axi_s0_byte_en_i, 
    input [(DATA_WIDTH - 1):0] axi_s0_wdata_i, 
    output axi_s0_wready_o, 
    input axi_s0_arpipeline_i, 
    input axi_s0_rd_en_i, 
    input [(ADDR_WIDTH - 1):0] axi_s0_raddr_i, 
    output axi_s0_rready_o, 
    // ------------------------------------------------------------------------------
    // Port S1 Signals
    // ------------------------------------------------------------------------------
    input axi_s1_awpipeline_i, 
    input [(ADDR_WIDTH - 1):0] axi_s1_waddr_i, 
    input axi_s1_wr_en_i, 
    input [(BYTE_WIDTH - 1):0] axi_s1_byte_en_i, 
    input [(DATA_WIDTH - 1):0] axi_s1_wdata_i, 
    output axi_s1_wready_o, 
    input axi_s1_arpipeline_i, 
    input axi_s1_rd_en_i, 
    input [(ADDR_WIDTH - 1):0] axi_s1_raddr_i, 
    output axi_s1_rready_o, 
    // ------------------------------------------------------------------------------
    // Arbitration
    // ------------------------------------------------------------------------------
    output [(ADDR_WIDTH - 1):0] arb_mem_awaddr_o, 
    output [(DATA_WIDTH - 1):0] arb_mem_wdata_o, 
    output arb_mem_wr_en_o, 
    output [(BYTE_WIDTH - 1):0] arb_mem_byte_en_o, 
    output [(ADDR_WIDTH - 1):0] arb_mem_araddr_o, 
    output arb_mem_rd_en_o, 
    // Atomic Access
    output [(ADDR_WIDTH - 1):0] addr_lock_start_s0, 
    output [(ADDR_WIDTH - 1):0] addr_lock_end_s0, 
    output target_locked_s0, 
    input target_avail_s0, 
    input target_clear_s0, 
    input [(ADDR_WIDTH - 1):0] req_lock_addr_start_s0, 
    input [(ADDR_WIDTH - 1):0] req_lock_addr_end_s0, 
    output [(ADDR_WIDTH - 1):0] addr_lock_start_s1, 
    output [(ADDR_WIDTH - 1):0] addr_lock_end_s1, 
    output target_locked_s1, 
    input target_avail_s1, 
    input target_clear_s1, 
    input [(ADDR_WIDTH - 1):0] req_lock_addr_start_s1, 
    input [(ADDR_WIDTH - 1):0] req_lock_addr_end_s1, 
    input axi_s0_awlock_i, 
    input axi_s1_awlock_i) ;
    // ------------------------------------------------------------------------------
    // Registers
    // ------------------------------------------------------------------------------
    reg axi_s0_wready_reg ; 
    reg axi_s1_wready_reg ; 
    reg axi_s0_rready_reg ; 
    reg axi_s1_rready_reg ; 
    reg [(ADDR_WIDTH - 1):0] addr_lock_start_s0_reg ; 
    reg [(ADDR_WIDTH - 1):0] addr_lock_end_s0_reg ; 
    reg target_locked_s0_reg ; 
    reg [(ADDR_WIDTH - 1):0] addr_lock_start_s1_reg ; 
    reg [(ADDR_WIDTH - 1):0] addr_lock_end_s1_reg ; 
    reg target_locked_s1_reg ; 
    wire wr_s0_gt_lock_s0 ; 
    wire wr_s0_lt_lock_s0 ; 
    wire wr_s1_gt_lock_s0 ; 
    wire wr_s1_lt_lock_s0 ; 
    wire wr_s0_gt_lock_s1 ; 
    wire wr_s0_lt_lock_s1 ; 
    wire wr_s1_gt_lock_s1 ; 
    wire wr_s1_lt_lock_s1 ; 
    // ------------------------------------------------------------------------------
    // State Machine Parameters
    // ------------------------------------------------------------------------------
    localparam IDLE = 2'd0 ; 
    localparam GRANT_S0 = 2'd1 ; 
    localparam GRANT_S1 = 2'd2 ; 
    // -----------------------------------------------------------------------------
    // Generate Blocks
    // -----------------------------------------------------------------------------
    //------------------------------
    // AXI Interfaces Arbiteration
    //------------------------------
    generate
        if ((PORT_TYPE_S1 == "DISABLED")) 
            begin : _single_port
                always
                    @(posedge clk_i or 
                        negedge rstn_i)
                    begin
                        if ((~rstn_i)) 
                            begin
                                axi_s0_wready_reg = 1'b0 ;
                                axi_s1_wready_reg = 1'b0 ;
                                axi_s0_rready_reg = 1'b0 ;
                                axi_s1_rready_reg = 1'b0 ;
                            end
                        else
                            begin
                                axi_s0_wready_reg = 1'b1 ;
                                axi_s1_wready_reg = 1'b0 ;
                                axi_s0_rready_reg = 1'b1 ;
                                axi_s1_rready_reg = 1'b0 ;
                            end
                    end
                assign arb_mem_awaddr_o = axi_s0_waddr_i ; 
                assign arb_mem_wdata_o = axi_s0_wdata_i ; 
                assign arb_mem_wr_en_o = axi_s0_wr_en_i ; 
                assign arb_mem_byte_en_o = axi_s0_byte_en_i ; 
                assign arb_mem_araddr_o = axi_s0_raddr_i ; 
                assign arb_mem_rd_en_o = axi_s0_rd_en_i ; 
            end
        else
            begin : _axi_arbitration
                reg [1:0] w_state ; 
                reg [1:0] w_state_next ; 
                reg [1:0] r_state ; 
                reg [1:0] r_state_next ; 
                reg w_s0_arb ; 
                reg w_s1_arb ; 
                wire axi_s0_awpipeline_d ; 
                assign axi_s0_awpipeline_d = ((PORT_TYPE_S0 == "R/W") ? axi_s0_awpipeline_i : 1'b0) ; 
                //------------------------------
                // Write
                //------------------------------
                always
                    @(posedge clk_i or 
                        negedge rstn_i)
                    begin
                        if ((~rstn_i)) 
                            begin
                                w_state <=  IDLE ;
                            end
                        else
                            begin
                                w_state <=  w_state_next ;
                            end
                    end
                always
                    @(*)
                    begin
                        case (w_state)
                        IDLE : 
                            begin
                                if (axi_s0_awpipeline_d) 
                                    begin
                                        w_state_next = GRANT_S0 ;
                                    end
                                else
                                    if (axi_s1_awpipeline_i) 
                                        begin
                                            w_state_next = GRANT_S1 ;
                                        end
                                    else
                                        begin
                                            w_state_next = IDLE ;
                                        end
                            end
                        GRANT_S0 : 
                            begin
                                if (axi_s0_awpipeline_d) 
                                    begin
                                        w_state_next = GRANT_S0 ;
                                    end
                                else
                                    if (axi_s1_awpipeline_i) 
                                        begin
                                            w_state_next = GRANT_S1 ;
                                        end
                                    else
                                        begin
                                            w_state_next = IDLE ;
                                        end
                            end
                        GRANT_S1 : 
                            begin
                                if (axi_s1_awpipeline_i) 
                                    begin
                                        w_state_next = GRANT_S1 ;
                                    end
                                else
                                    if (axi_s0_awpipeline_d) 
                                        begin
                                            w_state_next = GRANT_S0 ;
                                        end
                                    else
                                        begin
                                            w_state_next = IDLE ;
                                        end
                            end
                        default : 
                            w_state_next = IDLE ;
                        endcase 
                    end
                always
                    @(*)
                    begin
                        case (w_state)
                        IDLE : 
                            begin
                                axi_s0_wready_reg = 1'b1 ;
                                axi_s1_wready_reg = 1'b0 ;
                            end
                        GRANT_S0 : 
                            begin
                                axi_s0_wready_reg = 1'b1 ;
                                axi_s1_wready_reg = 1'b0 ;
                            end
                        GRANT_S1 : 
                            begin
                                axi_s0_wready_reg = 1'b0 ;
                                axi_s1_wready_reg = 1'b1 ;
                            end
                        default : 
                            begin
                                axi_s0_wready_reg = 1'b1 ;
                                axi_s1_wready_reg = 1'b0 ;
                            end
                        endcase 
                    end
                //------------------------------
                // Read
                //------------------------------
                always
                    @(posedge clk_i or 
                        negedge rstn_i)
                    begin
                        if ((~rstn_i)) 
                            r_state <=  IDLE ;
                        else
                            r_state <=  r_state_next ;
                    end
                always
                    @(*)
                    begin
                        r_state_next = r_state ;
                        case (r_state)
                        IDLE : 
                            begin
                                if ((axi_s0_arpipeline_i & axi_s0_rd_en_i)) 
                                    begin
                                        r_state_next = GRANT_S0 ;
                                    end
                                else
                                    if ((axi_s1_arpipeline_i & axi_s1_rd_en_i)) 
                                        begin
                                            r_state_next = GRANT_S1 ;
                                        end
                                    else
                                        begin
                                            r_state_next = IDLE ;
                                        end
                            end
                        GRANT_S0 : 
                            begin
                                if ((axi_s0_arpipeline_i & axi_s0_rd_en_i)) 
                                    begin
                                        r_state_next = GRANT_S0 ;
                                    end
                                else
                                    if ((axi_s1_arpipeline_i & axi_s1_rd_en_i)) 
                                        begin
                                            r_state_next = GRANT_S1 ;
                                        end
                                    else
                                        begin
                                            r_state_next = IDLE ;
                                        end
                            end
                        GRANT_S1 : 
                            begin
                                if ((axi_s1_arpipeline_i & axi_s1_rd_en_i)) 
                                    begin
                                        r_state_next = GRANT_S1 ;
                                    end
                                else
                                    if ((axi_s0_arpipeline_i & axi_s0_rd_en_i)) 
                                        begin
                                            r_state_next = GRANT_S0 ;
                                        end
                                    else
                                        begin
                                            r_state_next = IDLE ;
                                        end
                            end
                        default : 
                            begin
                                r_state_next = IDLE ;
                            end
                        endcase 
                    end
                always
                    @(*)
                    begin
                        case (r_state_next)
                        IDLE : 
                            begin
                                axi_s0_rready_reg = (~w_s1_arb) ;
                                axi_s1_rready_reg = (~w_s0_arb) ;
                            end
                        GRANT_S0 : 
                            begin
                                axi_s0_rready_reg = (~w_s1_arb) ;
                                axi_s1_rready_reg = 1'b0 ;
                            end
                        GRANT_S1 : 
                            begin
                                axi_s0_rready_reg = 1'b0 ;
                                axi_s1_rready_reg = (~w_s0_arb) ;
                            end
                        default : 
                            begin
                                axi_s0_rready_reg = (~w_s1_arb) ;
                                axi_s1_rready_reg = (~w_s0_arb) ;
                            end
                        endcase 
                    end
                assign arb_mem_awaddr_o = ((w_state_next == GRANT_S1) ? axi_s1_waddr_i : axi_s0_waddr_i) ; 
                assign arb_mem_wdata_o = ((w_state_next == GRANT_S1) ? axi_s1_wdata_i : axi_s0_wdata_i) ; 
                assign arb_mem_wr_en_o = ((w_state_next == GRANT_S1) ? axi_s1_wr_en_i : axi_s0_wr_en_i) ; 
                assign arb_mem_byte_en_o = ((w_state_next == GRANT_S1) ? axi_s1_byte_en_i : axi_s0_byte_en_i) ; 
                assign arb_mem_araddr_o = ((r_state_next == GRANT_S1) ? axi_s1_raddr_i : axi_s0_raddr_i) ; 
                assign arb_mem_rd_en_o = ((r_state_next == GRANT_S1) ? axi_s1_rd_en_i : axi_s0_rd_en_i) ; 
                // Write-Read Arbitration
                always
                    @(*)
                    begin
                        w_s0_arb = ((axi_s0_waddr_i == axi_s1_raddr_i) & axi_s0_awpipeline_i) ;
                        w_s1_arb = ((axi_s1_waddr_i == axi_s0_raddr_i) & axi_s1_awpipeline_i) ;
                    end
            end
    endgenerate
    // -----------------------------------------------------------------------------
    // Output Assignments
    // -----------------------------------------------------------------------------
    assign axi_s0_wready_o = axi_s0_wready_reg ; 
    assign axi_s0_rready_o = axi_s0_rready_reg ; // Read and write to the same address arbitration
    assign axi_s1_wready_o = axi_s1_wready_reg ; 
    assign axi_s1_rready_o = axi_s1_rready_reg ; 
    // ATOMIC ACCESS
    generate
        if (ATOMIC_ACCESS_EN_S0) 
            begin : genblk2
                assign addr_lock_start_s0 = addr_lock_start_s0_reg ; 
                assign addr_lock_end_s0 = addr_lock_end_s0_reg ; 
                assign target_locked_s0 = target_locked_s0_reg ; 
                // Registers
                always
                    @(posedge clk_i or 
                        negedge rstn_i)
                    begin
                        if ((~rstn_i)) 
                            begin
                                addr_lock_start_s0_reg <=  {ADDR_WIDTH{1'b0}} ;
                                addr_lock_end_s0_reg <=  {ADDR_WIDTH{1'b0}} ;
                            end
                        else
                            begin
                                if (target_clear_s0) 
                                    begin
                                        addr_lock_start_s0_reg <=  {ADDR_WIDTH{1'b0}} ;
                                        addr_lock_end_s0_reg <=  {ADDR_WIDTH{1'b0}} ;
                                    end
                                else
                                    if ((target_avail_s0 & axi_s0_rready_o)) 
                                        begin
                                            addr_lock_start_s0_reg <=  req_lock_addr_start_s0 ;
                                            addr_lock_end_s0_reg <=  req_lock_addr_end_s0 ;
                                        end
                                    else
                                        begin
                                            addr_lock_start_s0_reg <=  addr_lock_start_s0_reg ;
                                            addr_lock_end_s0_reg <=  addr_lock_end_s0_reg ;
                                        end
                            end
                    end
                assign wr_s0_gt_lock_s0 = (axi_s0_waddr_i >= addr_lock_start_s0_reg) ; 
                assign wr_s0_lt_lock_s0 = ((axi_s0_waddr_i < addr_lock_end_s0_reg) || (axi_s0_waddr_i == addr_lock_end_s0_reg)) ; 
                assign wr_s1_gt_lock_s0 = (axi_s1_waddr_i >= addr_lock_start_s0_reg) ; 
                assign wr_s1_lt_lock_s0 = ((axi_s1_waddr_i < addr_lock_end_s0_reg) || (axi_s1_waddr_i == addr_lock_end_s0_reg)) ; 
                always
                    @(posedge clk_i or 
                        negedge rstn_i)
                    begin
                        if ((~rstn_i)) 
                            begin
                                target_locked_s0_reg <=  1'b0 ;
                            end
                        else
                            begin
                                if (target_clear_s0) 
                                    begin
                                        target_locked_s0_reg <=  1'b0 ;
                                    end
                                else
                                    if ((((wr_s0_gt_lock_s0 & wr_s0_lt_lock_s0) & axi_s0_wr_en_i) & (~axi_s0_awlock_i))) 
                                        begin
                                            target_locked_s0_reg <=  1'b0 ;
                                        end
                                    else
                                        if (((wr_s1_gt_lock_s0 & wr_s1_lt_lock_s0) & axi_s1_wr_en_i)) 
                                            begin
                                                target_locked_s0_reg <=  1'b0 ;
                                            end
                                        else
                                            if ((target_avail_s0 & axi_s0_rready_o)) 
                                                begin
                                                    target_locked_s0_reg <=  1'b1 ;
                                                end
                                            else
                                                begin
                                                    target_locked_s0_reg <=  target_locked_s0_reg ;
                                                end
                            end
                    end
            end
        else
            begin : genblk2
                assign addr_lock_start_s0 = {ADDR_WIDTH{1'b0}} ; 
                assign addr_lock_end_s0 = {ADDR_WIDTH{1'b0}} ; 
                assign target_locked_s0 = 1'b0 ; 
            end
        if (ATOMIC_ACCESS_EN_S1) 
            begin : genblk3
                assign addr_lock_start_s1 = addr_lock_start_s1_reg ; 
                assign addr_lock_end_s1 = addr_lock_end_s1_reg ; 
                assign target_locked_s1 = target_locked_s1_reg ; 
                // Registers
                always
                    @(posedge clk_i or 
                        negedge rstn_i)
                    begin
                        if ((~rstn_i)) 
                            begin
                                addr_lock_start_s1_reg <=  {ADDR_WIDTH{1'b0}} ;
                                addr_lock_end_s1_reg <=  {ADDR_WIDTH{1'b0}} ;
                            end
                        else
                            begin
                                if (target_clear_s1) 
                                    begin
                                        addr_lock_start_s1_reg <=  {ADDR_WIDTH{1'b0}} ;
                                        addr_lock_end_s1_reg <=  {ADDR_WIDTH{1'b0}} ;
                                    end
                                else
                                    if ((target_avail_s1 & axi_s1_rready_o)) 
                                        begin
                                            addr_lock_start_s1_reg <=  req_lock_addr_start_s1 ;
                                            addr_lock_end_s1_reg <=  req_lock_addr_end_s1 ;
                                        end
                                    else
                                        begin
                                            addr_lock_start_s1_reg <=  addr_lock_start_s1_reg ;
                                            addr_lock_end_s1_reg <=  addr_lock_end_s1_reg ;
                                        end
                            end
                    end
                assign wr_s0_gt_lock_s1 = (axi_s0_waddr_i >= addr_lock_start_s1_reg) ; 
                assign wr_s0_lt_lock_s1 = ((axi_s0_waddr_i < addr_lock_end_s1_reg) || (axi_s0_waddr_i == addr_lock_end_s1_reg)) ; 
                assign wr_s1_gt_lock_s1 = (axi_s1_waddr_i >= addr_lock_start_s1_reg) ; 
                assign wr_s1_lt_lock_s1 = ((axi_s1_waddr_i < addr_lock_end_s1_reg) || (axi_s1_waddr_i == addr_lock_end_s1_reg)) ; 
                always
                    @(posedge clk_i or 
                        negedge rstn_i)
                    begin
                        if ((~rstn_i)) 
                            begin
                                target_locked_s1_reg <=  1'b0 ;
                            end
                        else
                            begin
                                if (target_clear_s1) 
                                    begin
                                        target_locked_s1_reg <=  1'b0 ;
                                    end
                                else
                                    if (((wr_s0_gt_lock_s1 & wr_s0_lt_lock_s1) & axi_s0_wr_en_i)) 
                                        begin
                                            target_locked_s1_reg <=  1'b0 ;
                                        end
                                    else
                                        if ((((wr_s1_gt_lock_s1 & wr_s1_lt_lock_s1) & axi_s1_wr_en_i) & (~axi_s1_awlock_i))) 
                                            begin
                                                target_locked_s1_reg <=  1'b0 ;
                                            end
                                        else
                                            if ((target_avail_s1 & axi_s1_rready_o)) 
                                                begin
                                                    target_locked_s1_reg <=  1'b1 ;
                                                end
                                            else
                                                begin
                                                    target_locked_s1_reg <=  target_locked_s1_reg ;
                                                end
                            end
                    end
            end
        else
            begin : genblk3
                assign addr_lock_start_s1 = {ADDR_WIDTH{1'b0}} ; 
                assign addr_lock_end_s1 = {ADDR_WIDTH{1'b0}} ; 
                assign target_locked_s1 = 1'b0 ; 
            end
    endgenerate
endmodule



`timescale 1ns/1ps
