module sys_mem_ipgen_lscc_axi4mem_subordinate #(parameter ATOMIC_ACCESS_EN = 0, 
        parameter DATA_WIDTH = 32, 
        parameter ADDR_WIDTH = 32, 
        parameter ID_WIDTH = 4, 
        parameter AXI_LEN_WIDTH = 8, 
        parameter BRESP_WIDTH = 2, 
        parameter MEMORY_TYPE = "EBR", 
        parameter ACCESS_TYPE = "R/W", 
        parameter BYTE_WIDTH = (DATA_WIDTH / 8), 
        parameter REG_MODE = "noreg", 
        parameter START_ADDR = 0, 
        parameter END_ADDR = 4096) (
    // -----------------------------------------------------------------------------
    // Parameters
    // -----------------------------------------------------------------------------
    // ------------------------------------------------------------------------------
    // Input/Output Ports
    // ------------------------------------------------------------------------------
    //Clock and Reset
    input aclk_i, 
    input aresetn_i, 
    //Write Address Channel (AW)
    input [(ID_WIDTH - 1):0] axi_awid_i, 
    input [31:0] axi_awaddr_i, 
    input [7:0] axi_awlen_i, 
    input [2:0] axi_awsize_i, 
    input [1:0] axi_awburst_i, 
    input axi_awlock_i, 
    input [3:0] axi_awcache_i, 
    input [2:0] axi_awprot_i, 
    input axi_awvalid_i, 
    output reg axi_awready_o, 
    //Write Data Channel (W)
    input [(DATA_WIDTH - 1):0] axi_wdata_i, 
    input [(BYTE_WIDTH - 1):0] axi_wstrb_i, 
    input axi_wlast_i, 
    input axi_wvalid_i, 
    output axi_wready_o, 
    //Write Response Channel (B)
    output [(ID_WIDTH - 1):0] axi_bid_o, 
    output [1:0] axi_bresp_o, 
    output axi_bvalid_o, 
    input axi_bready_i, 
    //Read Address Channel (AR)
    input [(ID_WIDTH - 1):0] axi_arid_i, 
    input [31:0] axi_araddr_i, 
    input [7:0] axi_arlen_i, 
    input [2:0] axi_arsize_i, 
    input [1:0] axi_arburst_i, 
    input axi_arlock_i, 
    input [3:0] axi_arcache_i, 
    input [2:0] axi_arprot_i, 
    input axi_arvalid_i, 
    output axi_arready_o, 
    //Read Data Channel (R)
    output [(ID_WIDTH - 1):0] axi_rid_o, 
    output reg [(DATA_WIDTH - 1):0] axi_rdata_o, 
    output [1:0] axi_rresp_o, 
    output axi_rlast_o, 
    output axi_rvalid_o, 
    input axi_rready_i, 
    // Arbiter
    input arb_awready_i, 
    input arb_wready_i, 
    input arb_rready_i, 
    output arb_awpipe_en, 
    output arb_arpipe_en, 
    // Memory Interface           
    input [(DATA_WIDTH - 1):0] mem_rdata_i, 
    input mem_error_i, 
    output reg mem_wr_en_o, 
    output [(ADDR_WIDTH - 1):0] mem_waddr_o, 
    output reg [(DATA_WIDTH - 1):0] mem_wdata_o, 
    output reg [(BYTE_WIDTH - 1):0] mem_byte_en_o, 
    output reg mem_rd_en_o, 
    output [(ADDR_WIDTH - 1):0] mem_raddr_o, 
    // Locked - Arbiter
    input [(ADDR_WIDTH - 1):0] addr_lock_start, 
    input [(ADDR_WIDTH - 1):0] addr_lock_end, 
    input target_locked, 
    input target_locked_sub, 
    output reg target_avail, 
    output reg target_clear, 
    output wire [(ADDR_WIDTH - 1):0] req_lock_addr_start, 
    output wire [(ADDR_WIDTH - 1):0] req_lock_addr_end, 
    output wire awlock_o) ;
    // ------------------------------------------------------------------------------
    // Local Parameters
    // ------------------------------------------------------------------------------
    localparam ADDR_INCR_SIZE_WIDTH = clog2((DATA_WIDTH / 8)) ; 
    localparam AWREQDWID = (((((ID_WIDTH + ADDR_WIDTH) + AXI_LEN_WIDTH) + 3) + 2) + 1) ; 
    localparam AXI4_STB_WIDTH = (DATA_WIDTH / 8) ; 
    localparam WDATQDWID = ((DATA_WIDTH + AXI4_STB_WIDTH) + 1) ; 
    localparam WRSPQDWID = (BRESP_WIDTH + ID_WIDTH) ; 
    localparam RDATQDWID = (((DATA_WIDTH + BRESP_WIDTH) + ID_WIDTH) + 1) ; 
    localparam READ_AFULLVL = ((REG_MODE == "noreg") ? 4 : 3) ; 
    // AxBURST
    localparam [1:0] FIXED = 2'b00 ; 
    localparam [1:0] INCR = 2'b01 ; 
    localparam [1:0] WRAP = 2'b10 ; 
    localparam [1:0] RSRV = 2'b11 ; 
    // AxSIZE
    localparam [2:0] X1_BYTE = 3'b000 ; 
    localparam [2:0] X2_BYTE = 3'b001 ; 
    localparam [2:0] X4_BYTE = 3'b010 ; 
    localparam [2:0] X8_BYTE = 3'b011 ; 
    // B Response
    localparam [1:0] AXI_RESP_OKAY = 2'b00 ; 
    localparam [1:0] AXI_RESP_EXOKAY = 2'b01 ; 
    localparam [1:0] AXI_RESP_SLVERR = 2'b10 ; 
    localparam [1:0] AXI_RESP_DECERR = 2'b11 ; 
    // ADDR LENGTH
    localparam [5:0] ADDR_WIDTH_LEN = (ADDR_WIDTH - 1) ; 
    // ------------------------------------------------------------------------------
    // Register Declarations
    // ------------------------------------------------------------------------------
    wire [(ID_WIDTH - 1):0] awid ; 
    wire [(ADDR_WIDTH - 1):0] awaddr ; 
    wire [7:0] awlen ; 
    wire [2:0] awsize ; 
    wire [1:0] awburst ; 
    wire awlock ; 
    wire [(AWREQDWID - 1):0] axi4_wreqinfo_in ; 
    wire [(AWREQDWID - 1):0] axi4_wreqinfo_out ; 
    wire axi4_awreq_wren ; 
    wire axi4_awreq_rden ; 
    wire axi4_awreq_done ; 
    wire axi4_awreq_emty ; 
    wire axi4_awreq_full ; 
    wire [(WDATQDWID - 1):0] axi4_wdata_in ; 
    wire [(WDATQDWID - 1):0] axi4_wdata_out ; 
    wire axi4_wdatq_emty ; 
    wire axi4_wdatq_full ; 
    wire [(BYTE_WIDTH - 1):0] wstrb ; 
    wire [(DATA_WIDTH - 1):0] wdata ; 
    wire wlast ; 
    reg wlast_reg ; 
    wire axi4_wdatq_done ; 
    wire axi_wr_valid ; 
    wire axi4_wdatq_wren ; 
    reg [31:0] mem_waddr_r ; 
    wire [31:0] req_lock_addr_start_r ; 
    reg [31:0] req_lock_addr_end_r ; 
    reg [(ADDR_WIDTH - 1):0] awwrap_lower_bound ; 
    reg [3:0] wincr_size_r ; 
    reg wr_active ; 
    reg awaddr_wrap_chk ; 
    wire [(WRSPQDWID - 1):0] axi4_wrspq_info_in ; 
    wire [(WRSPQDWID - 1):0] axi4_wrspq_info_out ; 
    wire [(BRESP_WIDTH - 1):0] bresp ; 
    wire [(ID_WIDTH - 1):0] bid ; 
    wire axi4_wrspq_emty ; 
    wire axi4_wrspq_full ; 
    wire axi4_wrspq_wren ; 
    wire axi4_wrspq_done ; 
    wire unsupported_reserved_d ; 
    reg unsupported_reserved ; 
    wire axi4_arreq_wren ; 
    wire axi4_arreq_done ; 
    wire axi4_arreq_full ; 
    wire axi4_arreq_emty ; 
    wire [(AWREQDWID - 1):0] axi4_rreqinfo_in ; 
    wire [(AWREQDWID - 1):0] axi4_rreqinfo_out ; 
    wire [(ID_WIDTH - 1):0] arid ; 
    wire [(ADDR_WIDTH - 1):0] araddr ; 
    wire [(AXI_LEN_WIDTH - 1):0] arlen ; 
    wire [2:0] arsize ; 
    wire [1:0] arburst ; 
    wire arlock ; 
    wire [AXI_LEN_WIDTH:0] eff_arlen ; 
    reg slave_err ; 
    // Exclusive Read
    reg exclusive_okay ; 
    wire axi4_axreq_wren ; 
    wire axi4_axreq_done ; 
    wire axi4_axreq_full ; 
    wire axi4_axreq_emty ; 
    wire [(AWREQDWID - 1):0] axi4_xreqinfo_in ; 
    wire [(AWREQDWID - 1):0] axi4_xreqinfo_out ; 
    wire [(ID_WIDTH - 1):0] axid ; 
    wire [(ADDR_WIDTH - 1):0] axaddr ; 
    wire [(AXI_LEN_WIDTH - 1):0] axlen ; 
    wire [2:0] axsize ; 
    wire [1:0] axburst ; 
    wire axlock ; 
    // Exclusive Write
    reg exclusive_write_hit ; 
    reg exclusive_id_hit ; 
    reg axi4_rdatq_wren ; 
    wire [(RDATQDWID - 1):0] axi4_rrspq_info_in ; 
    wire [(RDATQDWID - 1):0] axi4_rrspq_info_out ; 
    wire axi4_rdatq_done ; 
    wire [1:0] axi4_rdatq_full ; 
    wire axi_rdatq_afull ; 
    wire axi_rdatq_full ; 
    wire axi4_rdatq_emty ; 
    wire [(DATA_WIDTH - 1):0] axi_rdata_in ; 
    wire axi_rd_valid ; 
    reg [(BRESP_WIDTH - 1):0] rresp ; 
    wire [(DATA_WIDTH - 1):0] axi_rdata_r ; 
    reg rlast ; 
    reg rlast_nxt ; 
    reg rlast_nxt_d ; 
    wire rlast_o ; 
    reg [31:0] mem_raddr_r ; 
    wire [31:0] mem_raddr_r_holder_0 ; 
    wire [31:0] mem_raddr_r_holder_1 ; 
    wire mem_rd_reached ; 
    wire mem_rd_almost_reached ; 
    reg [8:0] mem_rd_count ; 
    reg [(ADDR_WIDTH - 1):0] addr_incr ; 
    reg [(BYTE_WIDTH - 1):0] rd_byte_en ; 
    reg [(BYTE_WIDTH - 1):0] init_byte_en ; 
    reg [(BYTE_WIDTH - 1):0] rd_byte_en_next ; 
    reg csr_rdat_valid ; 
    reg csr_rdat_valid_d ; 
    reg araddr_wrap_chk ; 
    reg [(ADDR_WIDTH - 1):0] wrap_lower_bound ; 
    reg rd_active ; 
    reg radrdec_reserved_det ; 
    reg axi_rvalid_d ; 
    reg [3:0] i ; 
    reg target_avail_reg ; 
    wire [31:0] addr_lock_start_r ; 
    wire [31:0] addr_lock_end_r ; 
    assign addr_lock_start_r = {addr_lock_start,
                {ADDR_INCR_SIZE_WIDTH{1'b0}}} ; 
    assign addr_lock_end_r = {addr_lock_end,
                {ADDR_INCR_SIZE_WIDTH{1'b0}}} ; 
    // ------------------------------------------------------------------------------
    // Write Address Channel (AW)
    // ------------------------------------------------------------------------------
    assign axi4_wreqinfo_in = (ATOMIC_ACCESS_EN ? {axi_awid_i[(ID_WIDTH - 1):0],
                axi_awaddr_i[(ADDR_WIDTH - 1):0],
                axi_awlen_i[(AXI_LEN_WIDTH - 1):0],
                axi_awsize_i[2:0],
                axi_awburst_i[1:0],
                axi_awlock_i} : {axi_awid_i[(ID_WIDTH - 1):0],
                axi_awaddr_i[(ADDR_WIDTH - 1):0],
                axi_awlen_i[(AXI_LEN_WIDTH - 1):0],
                axi_awsize_i[2:0],
                axi_awburst_i[1:0],
                1'b0}) ; 
    assign axi4_awreq_wren = (axi_awvalid_i & axi_awready_o) ; 
    assign axi4_awreq_rden = (axi4_wrspq_done & (~axi4_awreq_emty)) ; 
    assign axi4_awreq_done = (axi4_wdatq_done & wlast) ; 
    always
        @(posedge aclk_i or 
            negedge aresetn_i)
        begin
            if ((~aresetn_i)) 
                begin
                    wlast_reg <=  1'b0 ;
                end
            else
                begin
                    wlast_reg <=  wlast ;
                end
        end
    always
        @(*)
        begin
            axi_awready_o = (~axi4_awreq_full) ;
        end
    // Ongoing Request processing
    assign {awid[(ID_WIDTH - 1):0],
                awaddr[(ADDR_WIDTH - 1):0],
                awlen[(AXI_LEN_WIDTH - 1):0],
                awsize[2:0],
                awburst[1:0],
                awlock} = axi4_wreqinfo_out ; 
    assign awlock_o = awlock ; 
    // Write Channel
    assign axi4_wdata_in = {axi_wlast_i,
                axi_wstrb_i[(BYTE_WIDTH - 1):0],
                axi_wdata_i[(DATA_WIDTH - 1):0]} ; 
    assign {wlast,
                wstrb[(BYTE_WIDTH - 1):0],
                wdata[(DATA_WIDTH - 1):0]} = axi4_wdata_out ; 
    assign axi_wr_valid = (((~axi4_awreq_emty) & (~axi4_wdatq_emty)) & (~axi4_wrspq_full)) ; 
    assign axi4_wdatq_wren = (axi_wvalid_i & axi_wready_o) ; 
    assign axi4_wdatq_done = axi_wr_valid ; 
    assign axi_wready_o = ((((~axi4_wdatq_full) & arb_wready_i) & (~axi4_awreq_emty)) & arb_awready_i) ; 
    always
        @(posedge aclk_i or 
            negedge aresetn_i)
        begin
            if ((!aresetn_i)) 
                begin
                    mem_wr_en_o <=  1'b0 ;
                end
            else
                begin
                    if (awlock) 
                        begin
                            mem_wr_en_o <=  (axi_wr_valid & (bresp == AXI_RESP_EXOKAY)) ;
                        end
                    else
                        begin
                            mem_wr_en_o <=  (axi_wr_valid & (bresp == AXI_RESP_OKAY)) ;
                        end
                end
        end
    always
        @(posedge aclk_i or 
            negedge aresetn_i)
        begin
            if ((!aresetn_i)) 
                begin
                    mem_byte_en_o <=  {BYTE_WIDTH{1'b0}} ;
                end
            else
                begin
                    mem_byte_en_o <=  ((MEMORY_TYPE == "LRAM") ? (~wstrb) : wstrb) ;
                end
        end
    always
        @(posedge aclk_i or 
            negedge aresetn_i)
        begin
            if ((!aresetn_i)) 
                begin
                    mem_wdata_o <=  {DATA_WIDTH{1'b0}} ;
                end
            else
                begin
                    mem_wdata_o <=  wdata ;
                end
        end
    // Write Address
    assign mem_waddr_o = mem_waddr_r[(ADDR_WIDTH - 1):ADDR_INCR_SIZE_WIDTH] ; 
    always
        @(posedge aclk_i or 
            negedge aresetn_i)
        begin
            if ((!aresetn_i)) 
                begin
                    mem_waddr_r <=  {32{1'b0}} ;
                end
            else
                begin
                    if ((~wr_active)) 
                        begin
                            // START OF WRITE
                            mem_waddr_r <=  (awaddr + START_ADDR) ;
                        end
                    else
                        if (mem_wr_en_o) 
                            begin
                                //RESERVE
                                case (awburst)
                                FIXED : 
                                    mem_waddr_r <=  mem_waddr_r ;
                                INCR : 
                                    mem_waddr_r <=  (mem_waddr_r + {28'b0,
                                            wincr_size_r}) ;
                                WRAP : 
                                    mem_waddr_r <=  (awaddr_wrap_chk ? awwrap_lower_bound : (mem_waddr_r + {28'b0,
                                            wincr_size_r})) ;
                                default : 
                                    mem_waddr_r <=  mem_waddr_r ;
                                endcase 
                            end
                end
        end
    // Write state - if Write transaction is active
    always
        @(posedge aclk_i or 
            negedge aresetn_i)
        begin
            if ((!aresetn_i)) 
                begin
                    wr_active <=  1'b0 ;
                end
            else
                begin
                    if (axi_wr_valid) 
                        begin
                            wr_active <=  1'b1 ;
                        end
                    else
                        if (wlast_reg) 
                            begin
                                wr_active <=  1'b0 ;
                            end
                        else
                            begin
                                wr_active <=  wr_active ;
                            end
                end
        end
    generate
        if ((DATA_WIDTH == 8)) 
            begin : gen_w_incr_X8
                always
                    @(*)
                    case (awsize)
                    X1_BYTE : 
                        wincr_size_r = 4'd1 ;
                    default : 
                        wincr_size_r = 4'd1 ;
                    endcase 
            end
        else
            if ((DATA_WIDTH == 16)) 
                begin : gen_w_incr_X16
                    always
                        @(*)
                        case (awsize)
                        X1_BYTE : 
                            wincr_size_r = 4'd1 ;
                        X2_BYTE : 
                            wincr_size_r = (4'd2 - {3'd0,
                                    mem_waddr_r[0]}) ;
                        default : 
                            wincr_size_r = 4'd1 ;
