    // B Channel
    assign unsupported_reserved_d = (((ACCESS_TYPE == "R/O") | (awburst == RSRV)) | (mem_waddr_r > END_ADDR)) ; 
    always
        @(posedge aclk_i or 
            negedge aresetn_i)
        begin
            if ((!aresetn_i)) 
                begin
                    unsupported_reserved <=  1'b0 ;
                end
            else
                begin
                    if ((~axi4_awreq_done)) 
                        begin
                            unsupported_reserved <=  1'b0 ;
                        end
                    else
                        begin
                            unsupported_reserved <=  (unsupported_reserved ? 1'b1 : unsupported_reserved_d) ;
                        end
                end
        end
    // if atomic hit and lock should be 1 to respond EXOKAY
    assign bresp = ((unsupported_reserved | unsupported_reserved_d) ? AXI_RESP_SLVERR : ((exclusive_write_hit & target_locked) ? AXI_RESP_EXOKAY : AXI_RESP_OKAY)) ; 
    assign bid = awid ; 
    assign axi4_wrspq_info_in = {bresp[(BRESP_WIDTH - 1):0],
                bid[(ID_WIDTH - 1):0]} ; 
    assign {axi_bresp_o[(BRESP_WIDTH - 1):0],
                axi_bid_o[(ID_WIDTH - 1):0]} = axi4_wrspq_info_out ; 
    assign axi_bvalid_o = (~axi4_wrspq_emty) ; 
    assign axi4_wrspq_wren = axi4_awreq_done ; 
    assign axi4_wrspq_done = (axi_bvalid_o & axi_bready_i) ; 
    // AR Channel
    assign axi4_arreq_wren = (axi_arvalid_i & axi_arready_o) ; 
    assign axi_arready_o = (~axi4_arreq_full) ; 
    assign axi4_arreq_done = ((axi_rready_i & axi_rlast_o) & (~axi4_arreq_emty)) ; 
    assign axi4_rreqinfo_in = (ATOMIC_ACCESS_EN ? {axi_arid_i[(ID_WIDTH - 1):0],
                axi_araddr_i[(ADDR_WIDTH - 1):0],
                axi_arlen_i[(AXI_LEN_WIDTH - 1):0],
                axi_arsize_i[2:0],
                axi_arburst_i[1:0],
                axi_arlock_i} : {axi_arid_i[(ID_WIDTH - 1):0],
                axi_araddr_i[(ADDR_WIDTH - 1):0],
                axi_arlen_i[(AXI_LEN_WIDTH - 1):0],
                axi_arsize_i[2:0],
                axi_arburst_i[1:0],
                1'b0}) ; 
    assign {arid[(ID_WIDTH - 1):0],
                araddr[(ADDR_WIDTH - 1):0],
                arlen[(AXI_LEN_WIDTH - 1):0],
                arsize[2:0],
                arburst[1:0],
                arlock} = axi4_rreqinfo_out ; 
    // R Channel
    assign axi_rdatq_full = axi4_rdatq_full[1] ; 
    assign axi_rdatq_afull = axi4_rdatq_full[0] ; 
    assign axi_rd_valid = (((~axi4_arreq_emty) & (~axi_rdatq_afull)) & rd_active) ; 
    assign axi_rvalid_o = ((~axi4_rdatq_emty) & axi_rvalid_d) ; 
    assign axi4_rdatq_done = (axi_rvalid_o & axi_rready_i) ; 
    assign axi_rdata_in = ((~rresp[1]) ? mem_rdata_i : {DATA_WIDTH{1'b0}}) ; // OKAY OR EXOKAY
    assign axi4_rrspq_info_in = {rlast,
                rresp[(BRESP_WIDTH - 1):0],
                arid[(ID_WIDTH - 1):0],
                axi_rdata_in[(DATA_WIDTH - 1):0]} ; 
    always
        @(negedge aresetn_i or 
            posedge aclk_i)
        begin
            if ((~aresetn_i)) 
                begin
                    mem_rd_en_o <=  1'b0 ;
                end
            else
                begin
                    mem_rd_en_o <=  (((axi_rd_valid & (~axi_rlast_o)) & arb_rready_i) & (~mem_rd_reached)) ;
                end
        end
    generate
        if ((REG_MODE == "noreg")) 
            begin : no_gen_reg_mod_rd_data
                always
                    @(*)
                    begin
                        axi4_rdatq_wren = ((csr_rdat_valid & (~axi_rdatq_full)) & rd_active) ;// 1 clock cycle delay
                        rlast = rlast_nxt ;
                        slave_err = (((arburst == RSRV) | (mem_raddr_r > END_ADDR)) | (axi4_axreq_full & (arlock & (axid != arid)))) ;
                        // 1 if there is no standing EXCLUSIVE TRANSACTION or resetting monitored address and ATOMIC_ACCESS_EN 
                        exclusive_okay = (ATOMIC_ACCESS_EN ? ((((~axi4_axreq_full) || (axid == arid)) & arlock) & target_avail_reg) : 1'b0) ;
                    end
            end
        else
            begin : gen_reg_mod_rd_data
                always
                    @(posedge aclk_i or 
                        negedge aresetn_i)
                    begin
                        if ((!aresetn_i)) 
                            begin
                                csr_rdat_valid_d <=  1'b0 ;
                            end
                        else
                            begin
                                csr_rdat_valid_d <=  csr_rdat_valid ;
                            end
                    end
                always
                    @(posedge aclk_i or 
                        negedge aresetn_i)
                    begin
                        if ((!aresetn_i)) 
                            begin
                                rlast_nxt_d <=  1'b0 ;
                            end
                        else
                            begin
                                rlast_nxt_d <=  rlast_nxt ;
                            end
                    end
                always
                    @(*)
                    begin
                        axi4_rdatq_wren = (((~axi_rdatq_full) & csr_rdat_valid_d) & rd_active) ;
                        rlast = rlast_nxt_d ;
                    end
                always
                    @(posedge aclk_i or 
                        negedge aresetn_i)
                    begin
                        if ((~aresetn_i)) 
                            begin
                                slave_err <=  1'b0 ;
                                exclusive_okay <=  1'b0 ;
                            end
                        else
                            begin
                                slave_err <=  (((arburst == RSRV) | (mem_raddr_r > END_ADDR)) | (axi4_axreq_full & (arlock & (axid != arid)))) ;
                                // 1 if there is no standing EXCLUSIVE TRANSACTION or resetting monitored address and ATOMIC_ACCESS_EN 
                                exclusive_okay <=  (ATOMIC_ACCESS_EN ? ((((~axi4_axreq_full) || (axid == arid)) & arlock) & target_avail_reg) : 1'b0) ;
                            end
                    end
            end
    endgenerate
    always
        @(posedge aclk_i or 
            negedge aresetn_i)
        begin
            if ((!aresetn_i)) 
                begin
                    axi_rvalid_d <=  1'b0 ;
                end
            else
                begin
                    axi_rvalid_d <=  (~axi4_rdatq_emty) ;
                end
        end
    always
        @(posedge aclk_i or 
            negedge aresetn_i)
        begin
            if ((!aresetn_i)) 
                begin
                    csr_rdat_valid <=  1'b0 ;
                    rlast_nxt <=  1'b0 ;
                end
            else
                begin
                    csr_rdat_valid <=  (mem_rd_en_o & arb_rready_i) ;
                    rlast_nxt <=  mem_rd_almost_reached ;
                end
        end
    assign axi_rlast_o = (rlast_o & axi_rvalid_o) ; 
    assign {rlast_o,
                axi_rresp_o[(BRESP_WIDTH - 1):0],
                axi_rid_o[(ID_WIDTH - 1):0],
                axi_rdata_r[(DATA_WIDTH - 1):0]} = axi4_rrspq_info_out ; 
    always
        @(posedge aclk_i or 
            negedge aresetn_i)
        begin
            if ((~aresetn_i)) 
                begin
                    mem_rd_count <=  9'b0 ;
                end
            else
                begin
                    if ((!rd_active)) 
                        begin
                            mem_rd_count <=  9'b0 ;
                        end
                    else
                        begin
                            if ((mem_rd_en_o & arb_rready_i)) 
                                begin
                                    mem_rd_count <=  (mem_rd_count + 9'b1) ;
                                end
                            else
                                begin
                                    mem_rd_count <=  mem_rd_count ;
                                end
                        end
                end
        end
    assign mem_raddr_o = {{ADDR_INCR_SIZE_WIDTH{1'b0}},
                mem_raddr_r[(ADDR_WIDTH - 1):ADDR_INCR_SIZE_WIDTH]} ; 
    assign mem_raddr_r_holder_0 = (START_ADDR + araddr[(ADDR_WIDTH - 1):0]) ; 
    assign mem_raddr_r_holder_1 = (mem_raddr_r + addr_incr) ; 
    assign mem_rd_reached = (mem_rd_count >= eff_arlen) ; 
    assign mem_rd_almost_reached = (mem_rd_count == {1'b0,
                arlen}) ; 
    always
        @(posedge aclk_i or 
            negedge aresetn_i)
        begin
            if ((!aresetn_i)) 
                begin
                    mem_raddr_r <=  {32{1'b0}} ;
                end
            else
                begin
                    if ((!rd_active)) 
                        begin
                            mem_raddr_r <=  mem_raddr_r_holder_0 ;
                        end
                    else
                        if ((mem_rd_en_o & arb_rready_i)) 
                            begin
                                case (arburst)
                                FIXED : 
                                    mem_raddr_r <=  mem_raddr_r ;
                                INCR : 
                                    mem_raddr_r <=  mem_raddr_r_holder_1 ;
                                WRAP : 
                                    begin
                                        // Wrap Boundary
                                        mem_raddr_r <=  (araddr_wrap_chk ? wrap_lower_bound : mem_raddr_r_holder_1) ;
                                    end
                                default : 
                                    mem_raddr_r <=  mem_raddr_r ;
                                endcase 
                            end
                        else
                            begin
                                mem_raddr_r <=  mem_raddr_r ;
                            end
                end
        end
