    always
        @(*)
        begin
            for (i = 0 ; (i < BYTE_WIDTH) ; i = (i + 1))
                begin
                    if (rd_byte_en[i]) 
                        axi_rdata_o[(8 * i) +: 8] = axi_rdata_r[(8 * i) +: 8] ;
                    else
                        axi_rdata_o[(8 * i) +: 8] = 8'h00 ;
                end
        end
    always
        @(posedge aclk_i or 
            negedge aresetn_i)
        begin
            if ((!aresetn_i)) 
                begin
                    rd_byte_en <=  {BYTE_WIDTH{1'b0}} ;
                end
            else
                begin
                    if ((!rd_active)) 
                        begin
                            // START READ BYTE ENABLE
                            rd_byte_en <=  init_byte_en ;
                        end
                    else
                        begin
                            if (axi4_rdatq_done) 
                                begin
                                    rd_byte_en <=  ((arburst == FIXED) ? rd_byte_en : rd_byte_en_next) ;
                                end
                        end
                end
        end
    generate
        always
            @(*)
            begin
                if ((DATA_WIDTH == 8)) 
                    begin : gen_rd_byte_X8
                        rd_byte_en_next = rd_byte_en ;
                    end
                else
                    if ((DATA_WIDTH == 16)) 
                        begin : gen_rd_byte_X16
                            case (arsize)
                            X1_BYTE : 
                                rd_byte_en_next = {rd_byte_en[0],
                                        rd_byte_en[1]} ;
                            default : 
                                rd_byte_en_next = rd_byte_en ;
                            endcase 
                        end
                    else
                        if ((DATA_WIDTH == 32)) 
                            begin : gen_rd_byte_X32
                                case (arsize)
                                X1_BYTE : 
                                    rd_byte_en_next = {rd_byte_en[2:0],
                                            rd_byte_en[3]} ;
                                X2_BYTE : 
                                    rd_byte_en_next = {rd_byte_en[1:0],
                                            rd_byte_en[3:2]} ;
                                default : 
                                    rd_byte_en_next = rd_byte_en ;
                                endcase 
                            end
                        else
                            if ((DATA_WIDTH == 64)) 
                                begin : gen_rd_byte_X64
                                    // DATA_WIDTH==64 
                                    case (arsize)
                                    X1_BYTE : 
                                        rd_byte_en_next = {rd_byte_en[6:0],
                                                rd_byte_en[7]} ;
                                    X2_BYTE : 
                                        rd_byte_en_next = {rd_byte_en[5:0],
                                                rd_byte_en[7:6]} ;
                                    X4_BYTE : 
                                        rd_byte_en_next = {rd_byte_en[3:0],
                                                rd_byte_en[7:4]} ;
                                    default : 
                                        rd_byte_en_next = rd_byte_en ;
                                    endcase 
                                end
                            else
                                begin
                                    rd_byte_en_next = {BYTE_WIDTH{1'b0}} ;
                                end
            end
