    generate
        always
            @(*)
            begin
                if ((DATA_WIDTH == 8)) 
                    begin : gen_rd_init_byte_X8
                        init_byte_en = 1'b1 ;
                    end
                else
                    if ((DATA_WIDTH == 16)) 
                        begin : gen_rd_init_byte_X16
                            if ((arsize == 3'b000)) 
                                begin
                                    init_byte_en = (2'b1 << araddr[0]) ;
                                end
                            else
                                begin
                                    init_byte_en = 2'b11 ;
                                end
                        end
                    else
                        if ((DATA_WIDTH == 32)) 
                            begin : gen_rd_init_byte_X32
                                if ((arsize == 3'b000)) 
                                    begin
                                        init_byte_en = (4'b1 << araddr[1:0]) ;
                                    end
                                else
                                    if ((arsize == 3'b001)) 
                                        begin
                                            init_byte_en = (4'b11 << {araddr[1],
                                                    1'b0}) ;
                                        end
                                    else
                                        begin
                                            init_byte_en = 4'b1111 ;
                                        end
                            end
                        else
                            begin : gen_rd_init_byte_X64
                                // DATA_WIDTH == 64
                                if ((arsize == 3'b000)) 
                                    begin
                                        init_byte_en = (8'b1 << araddr[2:0]) ;
                                    end
                                else
                                    if ((arsize == 3'b001)) 
                                        begin
                                            init_byte_en = (8'b11 << {araddr[2:1],
                                                    1'b0}) ;
                                        end
                                    else
                                        if ((arsize == 3'b010)) 
                                            begin
                                                init_byte_en = (8'b1111 << {araddr[2],
                                                        2'b0}) ;
                                            end
                                        else
                                            begin
                                                init_byte_en = 8'b1111_1111 ;
                                            end
                            end
            end
