    assign req_lock_addr_start_r = (araddr + START_ADDR) ; 
    assign req_lock_addr_start = req_lock_addr_start_r[(ADDR_WIDTH - 1):ADDR_INCR_SIZE_WIDTH] ; 
    assign eff_arlen = ({1'b0,
                arlen} + {{AXI_LEN_WIDTH{1'b0}},
                1'b1}) ; 
    always
        @(*)
        begin
            // 8 bytes
            case (arsize)
            3'b000 : 
                req_lock_addr_end_r = ((req_lock_addr_start_r + eff_arlen) - {{ADDR_WIDTH_LEN{1'b0}},
                        1'b1}) ;
            3'b001 : 
                // 1 byte
                req_lock_addr_end_r = ((req_lock_addr_start_r + {eff_arlen,
                        1'b0}) - {{ADDR_WIDTH_LEN{1'b0}},
                        1'b1}) ;
            3'b010 : 
                // 2 bytes
                req_lock_addr_end_r = ((req_lock_addr_start_r + {eff_arlen,
                        2'b0}) - {{ADDR_WIDTH_LEN{1'b0}},
                        1'b1}) ;
            default : 
                // 4 bytes
                req_lock_addr_end_r = ((req_lock_addr_start_r + {eff_arlen,
                        3'b0}) - {{ADDR_WIDTH_LEN{1'b0}},
                        1'b1}) ;
            endcase 
        end
    assign req_lock_addr_end = req_lock_addr_end_r[(ADDR_WIDTH - 1):ADDR_INCR_SIZE_WIDTH] ; 
    generate
        if (ATOMIC_ACCESS_EN) 
            begin : genblk3
                always
                    @(posedge aclk_i or 
                        negedge aresetn_i)
                    begin
                        if ((~aresetn_i)) 
                            begin
                                target_avail_reg <=  1'b0 ;
                            end
                        else
                            begin
                                if (arlock) 
                                    begin
                                        if ((req_lock_addr_start_r < addr_lock_start_r)) 
                                            begin
                                                if ((req_lock_addr_end_r < addr_lock_start_r)) 
                                                    begin
                                                        target_avail_reg <=  arb_rready_i ;
                                                    end
                                                else
                                                    begin
                                                        target_avail_reg <=  (~target_locked_sub) ;
                                                    end
                                            end
                                        else
                                            if ((req_lock_addr_start_r > addr_lock_end_r)) 
                                                begin
                                                    target_avail_reg <=  arb_rready_i ;
                                                end
                                            else
                                                begin
                                                    target_avail_reg <=  (~target_locked_sub) ;
                                                end
                                    end
                                else
                                    begin
                                        target_avail_reg <=  1'b0 ;
                                    end
                            end
                    end
                always
                    @(*)
                    begin
                        target_avail = (target_avail_reg & mem_rd_en_o) ;
                    end
                always
                    @(*)
                    begin
                        target_clear = axi4_axreq_done ;
                    end
            end
        else
            begin : genblk3
                always
                    @(*)
                    begin
                        target_avail = 1'b0 ;
                        target_clear = 1'b0 ;
                        target_avail_reg = 1'b0 ;
                    end
            end
    endgenerate
    always
        @(posedge aclk_i or 
            negedge aresetn_i)
        begin
            if ((~aresetn_i)) 
                begin
                    rresp <=  2'b0 ;
                end
            else
                begin
                    rresp <=  (slave_err ? AXI_RESP_SLVERR : (exclusive_okay ? AXI_RESP_EXOKAY : AXI_RESP_OKAY)) ;
                end
        end
    always
        @(posedge aclk_i or 
            negedge aresetn_i)
        begin
            if ((!aresetn_i)) 
                begin
                    rd_active <=  1'b0 ;
                end
            else
                begin
                    if (axi4_arreq_done) 
                        begin
                            rd_active <=  1'b0 ;
                        end
                    else
                        if (((~axi4_arreq_emty) & arb_rready_i)) 
                            begin
                                rd_active <=  1'b1 ;
                            end
                end
        end
    // Pipeline Active
    assign arb_awpipe_en = ((~axi4_awreq_emty) | (~axi4_wrspq_emty)) ; 
    assign arb_arpipe_en = (~axi4_arreq_emty) ; 
    // Exclusive Read
    generate
        if (ATOMIC_ACCESS_EN) 
            begin : gen_atomic_wire
                assign axi4_axreq_wren = ((axi_rresp_o == AXI_RESP_EXOKAY) & axi_rlast_o) ; 
                assign axi4_axreq_done = (((exclusive_write_hit | exclusive_id_hit) & axi_bvalid_o) & axi_bready_i) ; // After completion with exclusive write
                assign axi4_xreqinfo_in = axi4_rreqinfo_out ; 
                assign {axid[(ID_WIDTH - 1):0],
                            axaddr[(ADDR_WIDTH - 1):0],
                            axlen[(AXI_LEN_WIDTH - 1):0],
                            axsize[2:0],
                            axburst[1:0],
                            axlock} = axi4_xreqinfo_out ; 
                // Exclusive transaction hit
                always
                    @(posedge aclk_i or 
                        negedge aresetn_i)
                    begin
                        if ((~aresetn_i)) 
                            begin
                                exclusive_id_hit <=  1'b0 ;
                            end
                        else
                            begin
                                if (((axid == awid) & awlock)) 
                                    begin
                                        exclusive_id_hit <=  1'b1 ;
                                    end
                                else
                                    begin
                                        exclusive_id_hit <=  1'b0 ;
                                    end
                            end
                    end
                always
                    @(posedge aclk_i or 
                        negedge aresetn_i)
                    begin
                        if ((~aresetn_i)) 
                            begin
                                exclusive_write_hit <=  1'b0 ;
                            end
                        else
                            begin
                                if ((axi4_xreqinfo_out == axi4_wreqinfo_out)) 
                                    begin
                                        exclusive_write_hit <=  ((~axi4_axreq_emty) & (~axi4_awreq_emty)) ;
                                    end
                                else
                                    if ((axi_bvalid_o & axi_bready_i)) 
                                        begin
                                            exclusive_write_hit <=  1'b0 ;
                                        end
                                    else
                                        begin
                                            exclusive_write_hit <=  exclusive_write_hit ;
                                        end
                            end
                    end
            end
        else
            begin : no_gen_atomic_wire
                assign axi4_axreq_wren = 1'b0 ; 
                assign axi4_axreq_done = 1'b0 ; 
                assign axi4_xreqinfo_in = {AWREQDWID{1'b0}} ; 
                assign axi4_xreqinfo_out = {AWREQDWID{1'b0}} ; 
                assign axid = {ID_WIDTH{1'b0}} ; 
                assign axaddr = {ADDR_WIDTH{1'b0}} ; 
                assign axlen = {AXI_LEN_WIDTH{1'b0}} ; 
                assign axsize = {3{1'b0}} ; 
                assign axburst = {2{1'b0}} ; 
                assign axlock = 1'b0 ; 
                assign axi4_axreq_emty = 1'b1 ; 
                assign axi4_axreq_full = 1'b0 ; 
                always
                    @(*)
                    begin
                        exclusive_write_hit = 1'b0 ;
                        exclusive_id_hit = 1'b0 ;
                    end
            end
    endgenerate
    //------------------------------------------------------------------------------
    // FIFO
    //------------------------------------------------------------------------------
    // AW Channel
    sys_mem_ipgen_shreg_fifo #(.DWID(AWREQDWID),
            .RNUM(2)) u_axi4_awreq (// Inputs
            .clk(aclk_i), 
                .rst_n(aresetn_i), 
                .clr(1'b0), 
                .wren(axi4_awreq_wren), 
                .dtin(axi4_wreqinfo_in[(AWREQDWID - 1):0]), 
                .rden(axi4_awreq_rden), 
                // Outputs
            .dtout(axi4_wreqinfo_out[(AWREQDWID - 1):0]), 
                .emty(axi4_awreq_emty), 
                .full(axi4_awreq_full)) ; 
    // W Channel
    sys_mem_ipgen_shreg_fifo #(.DWID(WDATQDWID),
            .RNUM(4)) u_axi4_wdatq (// Inputs
            .clk(aclk_i), 
                .rst_n(aresetn_i), 
                .clr(1'b0), 
                .wren(axi4_wdatq_wren), 
                .dtin(axi4_wdata_in), 
                .rden(axi4_wdatq_done), 
                // Outputs
            .dtout(axi4_wdata_out), 
                .emty(axi4_wdatq_emty), 
                .full(axi4_wdatq_full)) ; 
    // B Channel
    sys_mem_ipgen_shreg_fifo #(.DWID(WRSPQDWID),
            .RNUM(1)) u_axi4_wrspq (// Inputs
            .clk(aclk_i), 
                .rst_n(aresetn_i), 
                .clr(1'b0), 
                .wren(axi4_wrspq_wren), 
                .dtin(axi4_wrspq_info_in[(WRSPQDWID - 1):0]), 
                .rden(axi4_wrspq_done), 
                // Outputs
            .dtout(axi4_wrspq_info_out[(WRSPQDWID - 1):0]), 
                .emty(axi4_wrspq_emty), 
                .full(axi4_wrspq_full)) ; 
    // AR Channel
    sys_mem_ipgen_shreg_fifo #(.DWID(AWREQDWID),
            .RNUM(2)) u_axi4_arreq (// Inputs
            .clk(aclk_i), 
                .rst_n(aresetn_i), 
                .clr(1'b0), 
                .wren(axi4_arreq_wren), 
                .dtin(axi4_rreqinfo_in[(AWREQDWID - 1):0]), 
                .rden(axi4_arreq_done), 
                // Outputs
            .dtout(axi4_rreqinfo_out[(AWREQDWID - 1):0]), 
                .emty(axi4_arreq_emty), 
                .full(axi4_arreq_full)) ; 
    // R Channel
    sys_mem_ipgen_shreg_fifo #(.ENAFULL(1),
            .DWID(RDATQDWID),
            .RNUM(6),
            .AFULLVL(READ_AFULLVL)) u_axi4_rdatq (// Inputs
            .clk(aclk_i), 
                .rst_n(aresetn_i), 
                .clr(axi4_arreq_done), 
                .wren(axi4_rdatq_wren), 
                .dtin(axi4_rrspq_info_in[(RDATQDWID - 1):0]), 
                .rden(axi4_rdatq_done), 
                // Outputs
            .dtout(axi4_rrspq_info_out[(RDATQDWID - 1):0]), 
                .emty(axi4_rdatq_emty), 
                .full(axi4_rdatq_full)) ; 
    generate
        if (ATOMIC_ACCESS_EN) 
            begin : gen_atomic
                // Exclusive Read Access 
                sys_mem_ipgen_shreg_fifo #(.DWID(AWREQDWID),
                        .RNUM(1)) u_axi4_axreq (// Inputs
                        .clk(aclk_i), 
                            .rst_n(aresetn_i), 
                            .clr(1'b0), 
                            .wren(axi4_axreq_wren), 
                            .dtin(axi4_xreqinfo_in[(AWREQDWID - 1):0]), 
                            .rden(axi4_axreq_done), 
                            // Outputs
                        .dtout(axi4_xreqinfo_out[(AWREQDWID - 1):0]), 
                            .emty(axi4_axreq_emty), 
                            .full(axi4_axreq_full)) ; 
            end
    endgenerate
    // Function Definition
    //------------------------------------------------------------------------------
    function [31:0] clog2 ; 
        input [31:0] value ; 
        reg [31:0] num ; 
        begin
            num = (value - 1) ;
            for (clog2 = 0 ; (num > 0) ; clog2 = (clog2 + 1))
                num = (num >> 1) ;
        end
    endfunction
endmodule



