module sys_mem_ipgen_lscc_axi4stream_rx #(parameter ADDR_DEPTH = 16384, 
        parameter ADDR_WIDTH = 32, 
        parameter FIFO_START = 0, 
        parameter DATA_WIDTH = 32, 
        parameter BYTE_WIDTH = (DATA_WIDTH / 8), 
        parameter MEM_TYPE = "EBR") (
    // ------------------------------------------------------------------------------
    // Input/Output Ports
    // ------------------------------------------------------------------------------
    input axis_rx_aclk_i, 
    input axis_rx_aresetn_i, 
    input axis_rx_tvalid_i, 
    input [(DATA_WIDTH - 1):0] axis_rx_tdata_i, 
    input [((DATA_WIDTH / 8) - 1):0] axis_rx_tstrb_i, 
    input axis_rx_tlast_i, 
    output reg axis_rx_wr_en_o, 
    output reg [(DATA_WIDTH - 1):0] axis_rx_wr_data_o, 
    output reg [(BYTE_WIDTH - 1):0] axis_rx_byte_en_o, 
    output [(ADDR_WIDTH - 1):0] axis_rx_wr_addr_o, 
    output axis_rx_arb_hold_o, 
    output axis_rx_tready_o) ;
    localparam ADDR_INCR_SIZE_WIDTH = clog2((DATA_WIDTH / 8)) ; 
    localparam AXI4_STB_WIDTH = (DATA_WIDTH / 8) ; 
    localparam WDATQDWID = ((DATA_WIDTH + AXI4_STB_WIDTH) + 1) ; 
    // ------------------------------------------------------------------------------
    // Register Declarations
    // ------------------------------------------------------------------------------
    wire [(WDATQDWID - 1):0] axi4_wdata_in ; 
    wire [(WDATQDWID - 1):0] axi4_wdata_out ; 
    wire axi4_wdatq_emty ; 
    wire axi4_wdatq_full ; 
    wire [(BYTE_WIDTH - 1):0] wstrb ; 
    wire [(DATA_WIDTH - 1):0] wdata ; 
    wire wlast ; 
    reg wlast_reg ; 
    wire axi4_wdatq_done ; 
    wire axi_wr_valid ; 
    wire axi4_wdatq_wren ; 
    reg [(ADDR_WIDTH - 1):0] mem_waddr_r ; 
    wire [3:0] wincr_size_r ; 
    reg axis_rx_arb_hold_reg ; 
    reg axis_rx_arb_hold2_reg ; 
    reg axis_rx_tready_reg ; 
    // ------------------------------------------------------------------------------
    // AXI4-Stream Logic
    // ------------------------------------------------------------------------------
    // Write Channel
    assign axi4_wdata_in = {axis_rx_tlast_i,
                axis_rx_tstrb_i[(BYTE_WIDTH - 1):0],
                axis_rx_tdata_i[(DATA_WIDTH - 1):0]} ; 
    assign {wlast,
                wstrb[(BYTE_WIDTH - 1):0],
                wdata[(DATA_WIDTH - 1):0]} = axi4_wdata_out ; 
    assign axi4_wdatq_wren = (axis_rx_tvalid_i & axis_rx_tready_o) ; 
    assign axi4_wdatq_done = (~axi4_wdatq_emty) ; 
    assign axis_rx_tready_o = ((~axi4_wdatq_full) & axis_rx_tready_reg) ; 
    sys_mem_ipgen_shreg_fifo #(.DWID(WDATQDWID),
            .RNUM(3)) u_axi4_wdatq (// Inputs
            .clk(axis_rx_aclk_i), 
                .rst_n(axis_rx_aresetn_i), 
                .clr(1'b0), 
                .wren(axi4_wdatq_wren), 
                .dtin(axi4_wdata_in), 
                .rden(axi4_wdatq_done), 
                // Outputs
            .dtout(axi4_wdata_out), 
                .emty(axi4_wdatq_emty), 
                .full(axi4_wdatq_full) /*AUTOINST*/) ; 
    always
        @(posedge axis_rx_aclk_i or 
            negedge axis_rx_aresetn_i)
        begin
            if ((~axis_rx_aresetn_i)) 
                begin
                    axis_rx_wr_en_o <=  1'b0 ;
                end
            else
                begin
                    axis_rx_wr_en_o <=  axi4_wdatq_done ;
                end
        end
    always
        @(posedge axis_rx_aclk_i or 
            negedge axis_rx_aresetn_i)
        begin
            if ((~axis_rx_aresetn_i)) 
                begin
                    axis_rx_byte_en_o <=  {BYTE_WIDTH{1'b0}} ;
                end
            else
                begin
                    axis_rx_byte_en_o <=  ((MEM_TYPE == "LRAM") ? (~wstrb) : wstrb) ;
                end
        end
    always
        @(posedge axis_rx_aclk_i or 
            negedge axis_rx_aresetn_i)
        begin
            if ((~axis_rx_aresetn_i)) 
                begin
                    axis_rx_wr_data_o <=  {DATA_WIDTH{1'b0}} ;
                end
            else
                begin
                    axis_rx_wr_data_o <=  wdata ;
                end
        end
    // Write Address
    assign axis_rx_wr_addr_o = mem_waddr_r[(ADDR_WIDTH - 1):ADDR_INCR_SIZE_WIDTH] ; 
    always
        @(posedge axis_rx_aclk_i or 
            negedge axis_rx_aresetn_i)
        begin
            if ((!axis_rx_aresetn_i)) 
                begin
                    mem_waddr_r <=  {ADDR_WIDTH{1'b0}} ;
                end
            else
                begin
                    if (wlast_reg) 
                        begin
                            // START OF WRITE
                            mem_waddr_r <=  FIFO_START ;
                        end
                    else
                        if (axis_rx_wr_en_o) 
                            begin
                                mem_waddr_r <=  (mem_waddr_r + {{(ADDR_WIDTH - 4){1'b0}},
                                        wincr_size_r}) ;
                            end
                end
        end
    always
        @(posedge axis_rx_aclk_i or 
            negedge axis_rx_aresetn_i)
        begin
            if ((~axis_rx_aresetn_i)) 
                begin
                    wlast_reg <=  1'b0 ;
                end
            else
                begin
                    wlast_reg <=  wlast ;
                end
        end
    assign wincr_size_r = ((DATA_WIDTH == 8) ? 4'd1 : ((DATA_WIDTH == 16) ? 4'd2 : ((DATA_WIDTH == 32) ? 4'd4 : 4'd8))) ; 
    always
        @(posedge axis_rx_aclk_i or 
            negedge axis_rx_aresetn_i)
        begin
            if ((~axis_rx_aresetn_i)) 
                begin
                    axis_rx_arb_hold_reg <=  1'b1 ;
                end
            else
                if (axis_rx_tvalid_i) 
                    begin
                        axis_rx_arb_hold_reg <=  1'b1 ;
                    end
                else
                    begin
                        axis_rx_arb_hold_reg <=  1'b0 ;
                    end
        end
    always
        @(posedge axis_rx_aclk_i or 
            negedge axis_rx_aresetn_i)
        begin
            if ((~axis_rx_aresetn_i)) 
                begin
                    axis_rx_arb_hold2_reg <=  1'b1 ;
                end
            else
                if (axis_rx_tvalid_i) 
                    begin
                        axis_rx_arb_hold2_reg <=  1'b1 ;
                    end
                else
                    if ((~axis_rx_arb_hold_reg)) 
                        begin
                            axis_rx_arb_hold2_reg <=  1'b0 ;
                        end
        end
    assign axis_rx_arb_hold_o = axis_rx_arb_hold2_reg ; 
    always
        @(posedge axis_rx_aclk_i or 
            negedge axis_rx_aresetn_i)
        begin
            if ((~axis_rx_aresetn_i)) 
                begin
                    axis_rx_tready_reg <=  1'b0 ;
                end
            else
                if ((~axis_rx_arb_hold2_reg)) 
                    begin
                        axis_rx_tready_reg <=  1'b0 ;
                    end
                else
                    begin
                        axis_rx_tready_reg <=  1'b1 ;
                    end
        end
    //------------------------------------------------------------------------------
    // Function Definition
    //------------------------------------------------------------------------------
    function [31:0] clog2 ; 
        input [31:0] value ; 
        reg [31:0] num ; 
        begin
            num = (value - 1) ;
            for (clog2 = 0 ; (num > 0) ; clog2 = (clog2 + 1))
                num = (num >> 1) ;
        end
    endfunction
endmodule



