module sys_mem_ipgen_lscc_fifo_streamer #(parameter ADDR_DEPTH = 16384, 
        parameter FIFO_START = 0, 
        parameter DATA_WIDTH = 32, 
        parameter BYTE_WIDTH = (DATA_WIDTH / 8), 
        parameter ADDR_WIDTH = clog2(((ADDR_DEPTH * BYTE_WIDTH) - BYTE_WIDTH)), 
        parameter MEM_TYPE = "EBR") (
    input fifo_clk_i, 
    input fifo_wr_en_i, 
    input [7:0] fifo_wr_data_i, 
    input fifo_rst_i, 
    output reg fifo_full_o, 
    output reg [(DATA_WIDTH - 1):0] mem_wdata_o, 
    output mem_clk_en_o, 
    output [(ADDR_WIDTH - 1):0] mem_addr_o, 
    output [(BYTE_WIDTH - 1):0] mem_byte_en_o) ;
    reg fifo_full_int_r ; 
    reg [(ADDR_WIDTH - 1):0] mem_addr_r ; 
    reg [ADDR_WIDTH:0] mem_addr_nxt_c ; 
    reg fifo_full_nxt_c ; 
    reg [(BYTE_WIDTH - 1):0] mem_byte_en_r ; 
    wire [(BYTE_WIDTH - 1):0] mem_byte_en_nxt_c ; 
    assign mem_addr_o = mem_addr_r[(ADDR_WIDTH - 1):0] ; 
    generate
        if (((MEM_TYPE == "Distributed_RAM") & (DATA_WIDTH > 8))) 
            begin : gen_wdata_dram
                reg mem_clk_reg ; 
                always
                    @(posedge fifo_clk_i or 
                        negedge fifo_rst_i)
                    begin
                        if ((~fifo_rst_i)) 
                            begin
                                mem_wdata_o <=  {DATA_WIDTH{1'b0}} ;
                                mem_clk_reg <=  1'b0 ;
                            end
                        else
                            begin
                                mem_clk_reg <=  ((~fifo_full_int_r) & fifo_wr_en_i) ;
                                if (fifo_wr_en_i) 
                                    begin
                                        mem_wdata_o <=  {fifo_wr_data_i,
                                                mem_wdata_o[(DATA_WIDTH - 1):8]} ;
                                    end
                            end
                    end
                assign mem_clk_en_o = (mem_clk_reg & (~fifo_full_o)) ; 
            end
        else
            begin : genblk1
                always
                    @(*)
                    begin
                        mem_wdata_o = {BYTE_WIDTH{fifo_wr_data_i}} ;
                    end
                assign mem_clk_en_o = ((~fifo_full_int_r) & fifo_wr_en_i) ; 
            end
    endgenerate
    generate
        if ((MEM_TYPE == "LRAM")) 
            begin : gen_mem_lram
                genvar i0 ; 
                for (i0 = 0;(i0 < BYTE_WIDTH);i0 = (i0 + 1))
                begin : genblk1
                    assign mem_byte_en_o[i0] = (fifo_full_o ? 1'b1 : (~mem_byte_en_r[i0])) ; 
                end
            end
        else
            begin : no_gen_mem_lram
                assign mem_byte_en_o = (fifo_full_o ? 1'b0 : mem_byte_en_r) ; 
            end
    endgenerate
    generate
        if ((DATA_WIDTH == 8)) 
            begin : gen_one_byte
                always
                    @(*)
                    begin
                        mem_addr_nxt_c = {1'b0,
                                mem_addr_r} ;
                        if (mem_clk_en_o) 
                            begin
                                mem_addr_nxt_c = (mem_addr_r + 1'b1) ;
                            end
                    end
                assign mem_byte_en_nxt_c = 1'b1 ; 
            end
        else
            begin : gen_more_byte
                always
                    @(*)
                    begin
                        mem_addr_nxt_c = {1'b0,
                                mem_addr_r} ;
                        if ((mem_clk_en_o & mem_byte_en_r[(BYTE_WIDTH - 1)])) 
                            begin
                                mem_addr_nxt_c = (mem_addr_r + 1'b1) ;
                            end
                    end
                assign mem_byte_en_nxt_c = (mem_clk_en_o ? {mem_byte_en_r[(BYTE_WIDTH - 2):0],
                            mem_byte_en_r[(BYTE_WIDTH - 1)]} : mem_byte_en_r) ; 
            end
    endgenerate
    always
        @(*)
        begin
            fifo_full_nxt_c = (fifo_full_int_r | (fifo_wr_en_i && (mem_addr_nxt_c == ADDR_DEPTH))) ;
        end
    always
        @(posedge fifo_clk_i or 
            negedge fifo_rst_i)
        begin
            if ((~fifo_rst_i)) 
                begin
                    mem_addr_r <=  FIFO_START ;
                    mem_byte_en_r <=  4'h1 ;
                    fifo_full_o <=  1'b0 ;
                    fifo_full_int_r <=  1'b0 ;
                end
            else
                begin
                    mem_addr_r <=  mem_addr_nxt_c[(ADDR_WIDTH - 1):0] ;
                    mem_byte_en_r <=  mem_byte_en_nxt_c ;
                    fifo_full_o <=  fifo_full_nxt_c ;
                    fifo_full_int_r <=  fifo_full_nxt_c ;
                end
        end
    //------------------------------------------------------------------------------
    // Function Definition
    //------------------------------------------------------------------------------
    function [31:0] clog2 ; 
        input [31:0] value ; 
        reg [31:0] num ; 
        begin
            num = (value - 1) ;
            for (clog2 = 0 ; (num > 0) ; clog2 = (clog2 + 1))
                num = (num >> 1) ;
        end
    endfunction
endmodule



