//---------------------------------------------------------------------
// Module: lscc_reset_async
//---------------------------------------------------------------------
// Copyright (c) 2024 by Lattice Semiconductor Corporation
//---------------------------------------------------------------------
//
//  Params:
//  + SYNC_STAGE    -   Number of register stages used in synchronizers
//                      Allowable range is from 2 to 4
//  + SIM_ASSERT_EN -   Assertion enable
//
//  Ports:
//  + src_rst_n     -   Source reset (active low)
//
//  + dest_clk      -   Destination clock
//  + dest_rst      -   Destination reset (active high)
//  + dest_rst_n    -   Destination reset (active low)
//
//---------------------------------------------------------------------
(* LATTICE_IP_MODULE=1 *) module sys_mem_ipgen_lscc_reset_async #(parameter SYNC_STAGE = 2, 
        parameter SIM_ASSERT_EN = 1'b1) (
    input wire src_rst_n, 
    input wire dest_clk, 
    output wire dest_rst_n, 
    (* syn_preserve=1 *) output wire dest_rst) ;
    (* syn_preserve=1 *) reg [(SYNC_STAGE - 1):0] rstn_sync ; 
    always
        @(posedge dest_clk or 
            negedge src_rst_n)
        begin
            if ((~src_rst_n)) 
                begin
                    rstn_sync <=  {SYNC_STAGE{1'b0}} ;
                end
            else
                begin
                    rstn_sync <=  {rstn_sync[(SYNC_STAGE - 2):0],
                            1'b1} ;
                end
        end
    assign dest_rst_n = rstn_sync[(SYNC_STAGE - 1)] ; 
    assign dest_rst = (~dest_rst_n) ; 
endmodule



