            .rst_a_i(rst_a_i), 
                .clk_en_a_i(clk_en_a_i), 
                .rdout_clken_a_i(rdout_clken_a_i), 
                .wr_en_a_i(wr_en_a_i), 
                .wr_data_a_i(wr_data_a_i), 
                .addr_a_i(addr_a_i), 
                .ben_a_i(ben_a_w), 
                .rd_data_a_o(mem_out_a_w), 
                .rd_datavalid_a_o(rd_datavalid_a_o), 
                .ecc_errdet_a_o(ecc_errdet_a_o), 
                // --------------------------
            // ----- Port B signals -----
            // --------------------------
            .rst_b_i(rst_b_i), 
                .clk_en_b_i(clk_en_b_i), 
                .rdout_clken_b_i(rdout_clken_b_i), 
                .wr_en_b_i(wr_en_b_i), 
                .wr_data_b_i(wr_data_b_i), 
                .addr_b_i(addr_b_i), 
                .ben_b_i(ben_b_w), 
                .rd_data_b_o(mem_out_b_w), 
                .rd_datavalid_b_o(rd_datavalid_b_o), 
                .ecc_errdet_b_o(ecc_errdet_b_o)) ; 
    function [31:0] clog2 ; 
        input [31:0] value ; 
        reg [31:0] num ; 
        begin
            num = (value - 1) ;
            for (clog2 = 0 ; (num > 0) ; clog2 = (clog2 + 1))
                num = (num >> 1) ;
        end
    endfunction
endmodule



`timescale 1ns/1ps
