//==========================================================================
// Module : shreg_fifo
//==========================================================================
module sys_mem_ipgen_shreg_fifo #(parameter IMPL_TYPE = "FIFOREG", 
        parameter DWID = 8, 
        parameter RNUM = 8, 
        parameter DWID_O = DWID, 
        parameter DEFAULT = {DWID{1'b0}}, 
        parameter ENAFULL = 0, 
        parameter ENAEMTY = 0, 
        parameter REGFULL = 1, 
        parameter REGEMTY = 1, 
        parameter AFULLVL = (RNUM - 1), 
        parameter AEMTLVL = 1, 
        parameter SHFTDT0 = ((RNUM > 1) ? 1 : 0), 
        parameter USEDTIN = 0, 
        parameter KEEPLDT = 1) (
    //--begin_param--
    //----------------------------
    // Parameters
    //----------------------------
    // "SHREG" or "FIFOREG"
    // input width
    // number of registers
    // output width
    // default register value
    // enable almost full signal
    // enable almost empty signal
    // register full signal
    // register empty signal
    // almost full level
    // almost empty level
    // SHREG only - shift last data
    // SHREG only - optimize pipe by reusing the dtin as last stage
    // - assumes that dtin is registered and retains value unless rden==1
    // Keep last data in FIFOREG
    //--end_param--
    //--begin_ports--
    //----------------------------
    // Inputs
    //----------------------------
    input clk, 
    input rst_n, 
    input clr, 
    input wren, 
    input [(DWID - 1):0] dtin, 
    input rden, 
    //----------------------------
    // Outputs
    //----------------------------
    output reg [(DWID_O - 1):0] dtout, 
    output reg [ENAEMTY:0] emty,  // aemty,emty
    output reg [ENAFULL:0] full // full,afull
        ) ;
    //--end_ports--
    /*
function integer clog2;
  input [31:0] value;
  reg   [31:0] num;
  integer      idx;
begin
  num = value - 1;
  for (idx=0; num>0; idx=idx+1) num = num>>1;
  clog2 = idx;
end
endfunction
*/
    //--------------------------------------------------------------------------
    //--- Local Parameters/Defines ---
    //--------------------------------------------------------------------------
    //--------------------------------------------------------------------------
    //--- Combinational Wire/Reg ---
    //--------------------------------------------------------------------------
    //--------------------------------------------------------------------------
    //--- Registers ---
    //--------------------------------------------------------------------------
    genvar i ; 
    generate
        if ((RNUM == 1)) 
            begin : gen_1reg
                reg stt_reg ; 
                wire clr_data ; 
                assign clr_data = (SHFTDT0 ? rden : 1'b0) ; 
                //--------------------------------------------
                //-- Combinatorial block --
                //--------------------------------------------
                always
                    @(*)
                    begin
                        full = stt_reg ;
                        emty = (~stt_reg) ;
                    end//--always @*--
                //--------------------------------------------
                //-- Sequential block --
                //--------------------------------------------
                always
                    @(posedge clk or 
                        negedge rst_n)
                    begin
                        if ((~rst_n)) 
                            begin
                                dtout <=  DEFAULT ;
                                /*AUTORESET*/
                                // Beginning of autoreset for uninitialized flops
                                stt_reg <=  1'h0 ;
                                // End of automatics
                            end
                        else
                            begin
                                if (((wren ^ rden) | clr)) 
                                    begin
                                        stt_reg <=  (wren & (~clr)) ;
                                    end
                                if ((wren | clr_data)) 
                                    begin
                                        dtout <=  (dtin & {DWID{wren}}) ;
                                    end
                            end
                    end//--always @(posedge clk or negedge rst_n)--
            end
        else
            begin : gen_multistage
                integer idx1 ; 
                if ((IMPL_TYPE == "SHREG")) 
                    begin : gen_shreg
                        localparam PWID = (RNUM * DWID) ; 
                        reg [(PWID - 1):0] pipe_nxt ; 
                        reg [(RNUM + 1):0] stt_nxt ; 
                        reg [((PWID + DWID) - 1):0] shftdat ; 
                        reg [(RNUM - 1):0] pipewr ; 
                        reg [(RNUM - 1):0] piperd ; 
                        reg [(RNUM - 1):0] piperw ; 
                        wire [RNUM:0] stt_shr ; 
                        wire [RNUM:0] stt_shl ; 
                        wire shift_lastdt ; 
                        wire [(RNUM + 1):0] stt_wire ; 
                        reg [(PWID - 1):0] pipe ; 
                        wire [(RNUM + 1):0] stt ; 
                        reg [(RNUM - 1):0] stt_reg ; 
                        assign stt_wire = (REGFULL ? stt : stt_nxt) ; 
                        assign stt = {stt_reg[(RNUM - 1)],
                                    stt_reg,
                                    stt_reg[0]} ; 
                        //--------------------------------------------
                        //-- Combinatorial block --
                        //--------------------------------------------
                        always
                            @(*)
                            begin
                                dtout = pipe[(DWID_O - 1):0] ;
                                full = (ENAFULL ? {stt_wire[RNUM],
                                        stt_wire[AFULLVL]} : stt_wire[RNUM]) ;
                                emty = (REGEMTY ? (ENAEMTY ? (~{stt[(AEMTLVL + 1)],
                                        stt[1]}) : (~stt[1])) : (ENAEMTY ? (~{stt_nxt[(AEMTLVL + 1)],
                                        stt_nxt[1]}) : (~stt_nxt[1]))) ;
                            end//--always @*--
                        assign stt_shr = {1'b0,
                                    stt_reg} ; 
                        assign stt_shl = {stt_reg,
                                    1'b1} ; 
                        //--------------------------------------------
                        //-- Combinatorial block --
                        //--------------------------------------------
                        always
                            @(*)
                            begin
                                stt_nxt = {stt_reg[(RNUM - 1)],
                                        stt_reg,
                                        stt_reg[0]} ;
                                if (clr) 
                                    stt_nxt[RNUM:1] = {RNUM{1'b0}} ;
                                else
                                    begin
                                        case ({wren,
                                                rden})
                                        2'b10 : 
                                            stt_nxt[RNUM:1] = stt_shl[(RNUM - 1):0] ;
                                        2'b01 : 
                                            stt_nxt[RNUM:1] = stt_shr[RNUM:1] ;
                                        default : 
                                            stt_nxt[RNUM:1] = stt_reg ;
                                        endcase 
                                    end
                            end//--always @*--
                        assign shift_lastdt = SHFTDT0 ; 
                        //--------------------------------------------
                        //-- Combinatorial block --
                        //--------------------------------------------
                        always
                            @(*)
                            begin
                                if (shift_lastdt) 
                                    shftdat = {{DWID{1'b0}},
                                            pipe} ;
                                else
                                    shftdat = {pipe[(PWID - 1):(PWID - DWID)],
                                            pipe} ;
                            end//--always @*--
                        //--------------------------------------------
                        //-- Combinatorial block --
                        //--------------------------------------------
                        always
                            @(*)
                            begin
                                pipewr = ((~stt_reg) & ((stt_reg << 1) | {{(RNUM - 1){1'b0}},
                                        1'b1})) ;
                                piperd = (({RNUM{shift_lastdt}} & stt_reg) | ({RNUM{(~shift_lastdt)}} & (stt_reg >> 1))) ;
                                piperw = (stt_reg & (~(stt_reg >> 1))) ;
                            end//--always @*--
                        //--------------------------------------------
                        //-- Combinatorial block --
                        //--------------------------------------------
                        always
                            @(*)
                            begin
                                for (idx1 = 0 ; (idx1 < RNUM) ; idx1 = (idx1 + 1))
                                    begin
                                        case ({wren,
                                                rden})
                                        2'b10 : 
                                            begin
                                                pipe_nxt[(idx1 * DWID) +: DWID] = (({DWID{pipewr[idx1]}} & dtin) | ({DWID{(~pipewr[idx1])}} & shftdat[(idx1 * DWID) +: DWID])) ;
                                            end
                                        2'b01 : 
                                            begin
                                                pipe_nxt[(idx1 * DWID) +: DWID] = (({DWID{piperd[idx1]}} & shftdat[((idx1 + 1) * DWID) +: DWID]) | ({DWID{(~piperd[idx1])}} & shftdat[(idx1 * DWID) +: DWID])) ;
                                            end
                                        2'b11 : 
                                            begin
                                                pipe_nxt[(idx1 * DWID) +: DWID] = ((({DWID{((~piperd[idx1]) & (~piperw[idx1]))}} & shftdat[(idx1 * DWID) +: DWID]) | ({DWID{(piperd[idx1] & (~piperw[idx1]))}} & shftdat[((idx1 + 1) * DWID) +: DWID])) | ({DWID{piperw[idx1]}} & dtin)) ;
                                            end
                                        default : 
                                            pipe_nxt = pipe ;
                                        endcase 
                                    end
                            end//--always @*--
                        //--------------------------------------------
                        //-- Sequential block --
                        //--------------------------------------------
                        always
                            @(posedge clk or 
                                negedge rst_n)
                            begin
                                if ((~rst_n)) 
                                    begin
                                        stt_reg <=  {RNUM{1'b0}} ;
                                        /*AUTORESET*/
                                    end
                                else
                                    begin
                                        stt_reg <=  stt_nxt[RNUM:1] ;
                                    end
                            end//--always @(posedge clk or negedge rst_n)--
                        if ((USEDTIN && (RNUM > 1))) 
                            begin : gen_usedtin
                                always
                                    @(posedge clk or 
                                        negedge rst_n)
                                    begin
                                        if ((~rst_n)) 
                                            begin
                                                pipe[((PWID - DWID) - 1):0] <=  {(RNUM - 1){DEFAULT}} ;
                                                /*AUTORESET*/
                                            end
                                        else
                                            begin
                                                pipe[((PWID - DWID) - 1):0] <=  pipe_nxt[((PWID - DWID) - 1):0] ;
                                            end
                                    end//--always @(posedge clk or negedge rst_n)--
                                always
                                    @(*)
                                    begin
                                        pipe[(PWID - 1):(PWID - DWID)] = dtin ;
                                    end//--always @*--
                            end
                        else
                            begin : gen_no_usedtin
                                always
                                    @(posedge clk or 
                                        negedge rst_n)
                                    begin
                                        if ((~rst_n)) 
                                            begin
                                                pipe <=  {RNUM{DEFAULT}} ;
                                                /*AUTORESET*/
                                            end
                                        else
                                            begin
                                                pipe <=  pipe_nxt ;
                                            end
                                    end//--always @(posedge clk or negedge rst_n)--
                            end
                    end
                else
                    begin : gen_fiforeg
                        localparam PTRWID = $clog2(RNUM) ; 
                        localparam CNTWID = $clog2((RNUM + 1)) ; 
                        (* syn_ramstyle="distributed" *) reg [(DWID - 1):0] memArray [(RNUM - 1):0] ; 
                        reg [(CNTWID - 1):0] size_cntr ; 
                        reg [(PTRWID - 1):0] wptr ; 
                        reg [(PTRWID - 1):0] rptr ; 
                        reg [(DWID - 1):0] memArray_nxt [(RNUM - 1):0] ; 
                        reg [(CNTWID - 1):0] size_cntr_nxt ; 
                        wire [(PTRWID - 1):0] wptr_nxt ; 
                        wire [(PTRWID - 1):0] wptr_incr ; 
                        wire [(PTRWID - 1):0] rptr_nxt ; 
                        wire [(PTRWID - 1):0] rptr_incr ; 
                        wire [(PTRWID - 1):0] max_cnt ; 
                        wire [(CNTWID - 1):0] full_cnt ; 
                        wire gnd_wire ; 
                        assign gnd_wire = 1'b0 ; 
                        assign max_cnt = ((RNUM - 1) & {PTRWID{1'b1}}) ; 
                        assign full_cnt = (RNUM & {CNTWID{1'b1}}) ; 
                        assign wptr_incr = (wptr + (wren & {PTRWID{1'b1}})) ; 
                        assign wptr_nxt = ((wptr == max_cnt) ? ({PTRWID{(~wren)}} & wptr) : wptr_incr) ; 
                        assign rptr_incr = (rptr + (rden & {PTRWID{1'b1}})) ; 
                        assign rptr_nxt = ((rptr == max_cnt) ? ({PTRWID{(~rden)}} & rptr) : rptr_incr) ; 
                        always
                            @(*)
                            begin
                                case ({wren,
                                        rden})
                                2'b01 : 
                                    size_cntr_nxt = (size_cntr - (1'b1 & {CNTWID{1'b1}})) ;
                                2'b10 : 
                                    size_cntr_nxt = (size_cntr + (1'b1 & {CNTWID{1'b1}})) ;
                                default : 
                                    size_cntr_nxt = size_cntr ;
                                endcase 
                            end//--always @*--
                        always
                            @(*)
                            begin
                                for (idx1 = 0 ; (idx1 < RNUM) ; idx1 = (idx1 + 1))
                                    begin
                                        memArray_nxt[idx1] = memArray[idx1] ;
                                    end
                                if (wren) 
                                    begin
                                        memArray_nxt[wptr] = dtin ;
                                    end
                            end//--always @*--
                        for (i = 0;(i < RNUM);i = (i + 1))
                        begin : gen_memreg
                            always
                            // gen_memreg
                                @(posedge clk or 
                                    negedge rst_n)
                                begin
                                    if ((~rst_n)) 
                                        begin
                                            memArray[i] <=  DEFAULT ;
                                            /*AUTORESET*/
                                        end
                                    else
                                        begin
                                            memArray[i] <=  memArray_nxt[i] ;
                                        end
                                end//--always @(posedge clk or negedge rst_n)--
                        end
                        always
                            @(posedge clk or 
                                negedge rst_n)
                            begin
                                if ((~rst_n)) 
                                    begin
                                        /*AUTORESET*/
                                        // Beginning of autoreset for uninitialized flops
                                        dtout <=  {DWID{1'b0}} ;
                                        rptr <=  {PTRWID{1'b0}} ;
                                        size_cntr <=  {CNTWID{1'b0}} ;
                                        wptr <=  {PTRWID{1'b0}} ;
                                        // End of automatics
                                    end
                                else
                                    begin
                                        wptr <=  (wptr_nxt & {PTRWID{(~clr)}}) ;
                                        rptr <=  (rptr_nxt & {PTRWID{(~clr)}}) ;
                                        size_cntr <=  (size_cntr_nxt & {CNTWID{(~clr)}}) ;
                                        if (((|size_cntr_nxt) | (KEEPLDT == 0))) 
                                            begin
                                                dtout <=  memArray_nxt[rptr_nxt] ;
                                            end
                                    end
                            end//--always @(posedge clk or negedge rst_n)--
                        if (ENAFULL) 
                            begin : gen_aful
                                always
                                    @(posedge clk or 
                                        negedge rst_n)
                                    begin
                                        if ((~rst_n)) 
                                            begin
                                                /*AUTORESET*/
                                                // Beginning of autoreset for uninitialized flops
                                                full <=  {(1 + ENAFULL){1'b0}} ;
                                                // End of automatics
                                            end
                                        else
                                            begin
                                                full[0] <=  ((~clr) & (size_cntr_nxt >= (AFULLVL & {CNTWID{1'b1}}))) ;// aful
                                                full[1] <=  ((~clr) & (size_cntr_nxt == full_cnt)) ;// full
                                            end
                                    end//--always @(posedge clk or negedge rst_n)--
                            end
                        else
                            begin : gen_noaful
                                always
                                    @(posedge clk or 
                                        negedge rst_n)
                                    begin
                                        if ((~rst_n)) 
                                            begin
                                                /*AUTORESET*/
                                                // Beginning of autoreset for uninitialized flops
                                                full <=  {(1 + ENAFULL){1'b0}} ;
                                                // End of automatics
                                            end
                                        else
                                            begin
                                                full <=  ((~clr) & (size_cntr_nxt == full_cnt)) ;// full
                                            end
                                    end//--always @(posedge clk or negedge rst_n)--
                            end
                        if (ENAEMTY) 
                            begin : gen_aemty
                                always
                                    @(posedge clk or 
                                        negedge rst_n)
                                    begin
                                        if ((~rst_n)) 
                                            begin
                                                emty <=  2'b11 ;
                                                /*AUTORESET*/
                                            end
                                        else
                                            begin
                                                emty[0] <=  (clr | (~|size_cntr_nxt)) ;// emty
                                                emty[1] <=  (clr | (size_cntr_nxt <= (AEMTLVL & {CNTWID{1'b1}}))) ;// aemty
                                            end
                                    end//--always @(posedge clk or negedge rst_n)--
                            end
                        else
                            begin : gen_noaemty
                                always
                                    @(posedge clk or 
                                        negedge rst_n)
                                    begin
                                        if ((~rst_n)) 
                                            begin
                                                emty <=  1'b1 ;
                                                /*AUTORESET*/
                                            end
                                        else
                                            begin
                                                emty <=  (clr | (~|size_cntr_nxt)) ;// emty
                                            end
                                    end//--always @(posedge clk or negedge rst_n)--
                            end
                    end
            end
    endgenerate

