                                .mem_wr_rdn_b_i(mem1_wr_rdn_arb_w), 
                                .mem_addr_b_i(mem1_addr_w), 
                                .mem_wdata_b_i(mem1_wdata_w), 
                                .mem_byte_en_b_i(mem1_byte_en_w)) ; 
                end
        end
    endgenerate
    // ------------------------   
    // Arbiter           
    // ------------------------ 
    if ((INTERFACE == "AXI4")) 
        begin : AXI4_ARB
            sys_mem_ipgen_lscc_axi4mem_arbiter #(.PORT_TYPE_S0(ACCESS_TYPE_S0),
                    .PORT_TYPE_S1(ACCESS_TYPE_S1),
                    .DATA_WIDTH(DATA_WIDTH),
                    .ADDR_WIDTH(ADDR_WIDTH),
                    .ARBITER_EN(ARBITER_EN),
                    .ATOMIC_ACCESS_EN_S0(ATOMIC_ACCESS_EN_S0),
                    .ATOMIC_ACCESS_EN_S1(ATOMIC_ACCESS_EN_S1)) u_arbiter (// Common Signal
                    .clk_i(axi_aclk_i), 
                        .rstn_i(axi_resetn_w), 
                        // Memory 0
                    .axi_s0_awpipeline_i(arb_s0_awpipe_o), 
                        .axi_s0_arpipeline_i(arb_s0_arpipe_o), 
                        .axi_s0_waddr_i(mem0_axi_waddr_o), 
                        .axi_s0_wr_en_i(mem0_axi_wr_en_o), 
                        .axi_s0_byte_en_i(mem0_axi_byte_en_o), 
                        .axi_s0_wdata_i(mem0_axi_wdata_o), 
                        .axi_s0_rd_en_i(mem0_axi_rd_en_o), 
                        .axi_s0_raddr_i(mem0_axi_raddr_o), 
                        .axi_s0_wready_o(arb_s0_wready_o), 
                        .axi_s0_rready_o(arb_s0_rready_o), 
                        // Memory 1
                    .axi_s1_awpipeline_i(arb_s1_awpipe_o), 
                        .axi_s1_arpipeline_i(arb_s1_arpipe_o), 
                        .axi_s1_waddr_i(mem1_axi_waddr_o), 
                        .axi_s1_wr_en_i(mem1_axi_wr_en_o), 
                        .axi_s1_byte_en_i(mem1_axi_byte_en_o), 
                        .axi_s1_wdata_i(mem1_axi_wdata_o), 
                        .axi_s1_rd_en_i(mem1_axi_rd_en_o), 
                        .axi_s1_raddr_i(mem1_axi_raddr_o), 
                        .axi_s1_wready_o(arb_s1_wready_o), 
                        .axi_s1_rready_o(arb_s1_rready_o), 
                        // Arbitration
                    .arb_mem_awaddr_o(arb_mem_awaddr_o), 
                        .arb_mem_wdata_o(arb_mem_wdata_o), 
                        .arb_mem_wr_en_o(arb_mem_wr_en_o), 
                        .arb_mem_byte_en_o(arb_mem_byte_en_o), 
                        .arb_mem_araddr_o(arb_mem_raddr_o),  // read address
                    .arb_mem_rd_en_o(arb_mem_rd_en_o), 
                        // ATOMIC ACCESS
                    .addr_lock_start_s0(addr_lock_start_s0), 
                        .addr_lock_end_s0(addr_lock_end_s0), 
                        .target_locked_s0(target_locked_s0), 
                        .target_avail_s0(target_avail_s0), 
                        .target_clear_s0(target_clear_s0), 
                        .req_lock_addr_start_s0(req_lock_addr_start_s0), 
                        .req_lock_addr_end_s0(req_lock_addr_end_s0), 
                        .addr_lock_start_s1(addr_lock_start_s1), 
                        .addr_lock_end_s1(addr_lock_end_s1), 
                        .target_locked_s1(target_locked_s1), 
                        .target_avail_s1(target_avail_s1), 
                        .target_clear_s1(target_clear_s1), 
                        .req_lock_addr_start_s1(req_lock_addr_start_s1), 
                        .req_lock_addr_end_s1(req_lock_addr_end_s1), 
                        .axi_s0_awlock_i(axi_s0_awlock), 
                        .axi_s1_awlock_i(axi_s1_awlock)) ; 
        end
    else
        begin : AHBL_ARB
            sys_mem_ipgen_lscc_ahblmem_arbiter #(.PORT_TYPE_S0(ACCESS_TYPE_S0),
                    .PORT_TYPE_S1(ACCESS_TYPE_S1),
                    .ADDR_WIDTH(ADDR_WIDTH),
                    .RESET_MODE((((RESET_MODE_S0 == "async") || (RESET_MODE_S1 == "async")) ? "async" : "sync")),
                    .ARBITER_EN(ARBITER_EN)) u_arbiter (// Common Signal
                    .clk_i(ahbl_hclk_i), 
                        .rst_i(ahbl_hresetn_w), 
                        // Memory 0 Signal
                    .addr_s0_i(mem0_addr_w), 
                        .mem_wr_rdn_s0_i(mem0_wr_rdn_w), 
                        .mem_req_s0_i(mem0_request_w), 
                        .mem_wr_rdn_s0_o(mem0_wr_rdn_arb_w), 
                        .mem_req_s0_o(mem0_req_arb_w), 
                        // Memory 1 Signal
                    .addr_s1_i(mem1_addr_w), 
                        .mem_wr_rdn_s1_i(mem1_wr_rdn_w), 
                        .mem_req_s1_i(mem1_request_w), 
                        .mem_wr_rdn_s1_o(mem1_wr_rdn_arb_w), 
                        .mem_req_s1_o(mem1_req_arb_w), 
                        // Arbiter Signal
                    .ahbl_ready_s0_o(arb_hready_s0_o), 
                        .ahbl_ready_s1_o(arb_hready_s1_o)) ; 
        end
    //------------------------------------------------------------------------------
    // Function Definition
    //------------------------------------------------------------------------------
    function [31:0] clog2 ; 
        input [31:0] value ; 
        reg [31:0] num ; 
        begin
            num = (value - 1) ;
            for (clog2 = 0 ; (num > 0) ; clog2 = (clog2 + 1))
                num = (num >> 1) ;
        end
    endfunction
endmodule


